let currentProfilId = null;

// ══ SYSTÈME DE POSTS ══
const _postsCache = {}; // { recordId: [{id, texte, photo, date, auteur}] }

function previewPostMedia(input, recordId) {
  const file = input?.files[0];
  if (!file) return;
  const preview = document.getElementById(`post-img-preview-${recordId}`);
  const imgEl   = document.getElementById(`post-img-preview-img-${recordId}`);
  const vidEl   = document.getElementById(`post-img-preview-vid-${recordId}`);
  if (!preview) return;

  if (file.type.startsWith('video/')) {
    // Vérifier durée max 3 min via metadata
    const blobUrl = URL.createObjectURL(file);
    const tmp = document.createElement('video');
    tmp.preload = 'metadata';
    tmp.onloadedmetadata = () => {
      URL.revokeObjectURL(blobUrl);
      if (tmp.duration > 180) {
        toast('La vidéo doit faire moins de 3 minutes (180s)', 'error');
        input.value = '';
        return;
      }
      if (imgEl) imgEl.style.display = 'none';
      if (vidEl) { vidEl.src = URL.createObjectURL(file); vidEl.style.display = 'block'; }
      preview.style.display = 'flex';
      preview.style.alignItems = 'center';
    };
    tmp.src = blobUrl;
  } else {
    const reader = new FileReader();
    reader.onload = (e) => {
      if (vidEl) vidEl.style.display = 'none';
      if (imgEl) { imgEl.src = e.target.result; imgEl.style.display = 'block'; }
      preview.style.display = 'flex';
      preview.style.alignItems = 'center';
    };
    reader.readAsDataURL(file);
  }
}
// Compat alias
function previewPostImg(input, recordId) { previewPostMedia(input, recordId); }

function clearPostMedia(recordId) {
  const input  = document.getElementById(`post-img-${recordId}`);
  const preview = document.getElementById(`post-img-preview-${recordId}`);
  const vidEl  = document.getElementById(`post-img-preview-vid-${recordId}`);
  if (input) input.value = '';
  if (vidEl) { vidEl.pause?.(); vidEl.src = ''; vidEl.style.display = 'none'; }
  if (preview) preview.style.display = 'none';
}
function clearPostImg(recordId) { clearPostMedia(recordId); }

// ══ UNIFICATION SOCIAL (étape 5) : UNE table wozali_posts + wozali_likes
// + wozali_commentaires. Les likes vivent en base, plus en localStorage. ══
async function wzFetchMyLikes(postIds) {
  if (!currentUser || !postIds.length) return new Set();
  try {
    const { data } = await window.supabase.from('wozali_likes').select('post_id').eq('user_id', currentUser.id).in('post_id', postIds);
    return new Set((data || []).map(r => r.post_id));
  } catch { return new Set(); }
}

async function wzToggleLike(postId, wantLike) {
  const supa = window.supabase;
  if (wantLike) {
    const { error } = await supa.from('wozali_likes').insert({ post_id: postId, user_id: currentUser.id });
    if (error && !String(error.message || '').toLowerCase().includes('duplicate')) throw error;
  } else {
    const { error } = await supa.from('wozali_likes').delete().eq('post_id', postId).eq('user_id', currentUser.id);
    if (error) throw error;
  }
}

// ── Réactions emoji (étape 14) : une réaction par personne, stockée dans wozali_likes ──
const WZ_REACTIONS = ['👏', '🔥', '❤️', '🙏'];

async function wzFetchMyReactions(postIds) {
  if (!currentUser || !postIds.length) return {};
  try {
    const { data } = await window.supabase.from('wozali_likes')
      .select('post_id, emoji').eq('user_id', currentUser.id).in('post_id', postIds);
    const map = {};
    (data || []).forEach(r => { map[r.post_id] = r.emoji || '❤️'; });
    return map;
  } catch { return {}; }
}

// Pose, change, ou retire la réaction de l'utilisateur. Renvoie le delta du compteur (+1/0/-1).
async function wzSetReaction(postId, emoji, currentEmoji) {
  const supa = window.supabase;
  if (currentEmoji === emoji) {
    // Re-tap le même emoji = on retire la réaction
    const { error } = await supa.from('wozali_likes').delete().eq('post_id', postId).eq('user_id', currentUser.id);
    if (error) throw error;
    return -1;
  }
  if (currentEmoji) {
    // Changement d'emoji : le total ne bouge pas
    const { error } = await supa.from('wozali_likes').update({ emoji }).eq('post_id', postId).eq('user_id', currentUser.id);
    if (error) throw error;
    return 0;
  }
  // Première réaction
  const { error } = await supa.from('wozali_likes').insert({ post_id: postId, user_id: currentUser.id, emoji });
  if (error && !String(error.message || '').toLowerCase().includes('duplicate')) throw error;
  return error ? 0 : 1;
}

// Barre de réactions inline : 4 emoji + total. Le mien est surligné.
function _wzReactionBar(postId, total, myEmoji) {
  const btns = WZ_REACTIONS.map(e => {
    const on = e === myEmoji;
    return `<button type="button" onclick="wzReact(event,'${postId}','${e}')" aria-label="Réagir ${e}"
      style="background:${on ? 'rgba(232,148,10,0.18)' : 'none'};border:${on ? '1px solid rgba(232,148,10,0.5)' : '1px solid transparent'};border-radius:100px;font-size:17px;line-height:1;padding:5px 8px;cursor:pointer;transition:transform .1s;"
      ontouchstart="" >${e}</button>`;
  }).join('');
  return `<div class="wz-react-bar" data-post="${postId}" data-mine="${myEmoji || ''}" style="display:flex;align-items:center;gap:2px;">
    ${btns}
    <span class="wz-react-total" style="font-size:12px;color:rgba(252,224,168,0.4);margin-left:6px;">${total > 0 ? total : ''}</span>
  </div>`;
}

async function wzReact(ev, postId, emoji) {
  if (ev) { ev.preventDefault(); ev.stopPropagation(); }
  if (!currentUser) { toast('Connecte-toi pour réagir.', 'info'); showPage('login'); return; }
  const bar = document.querySelector(`.wz-react-bar[data-post="${postId}"]`);
  if (!bar) return;
  const currentEmoji = bar.dataset.mine || '';
  const totalEl = bar.querySelector('.wz-react-total');
  let total = parseInt(totalEl.textContent || '0') || 0;

  // Optimiste : on met à jour l'écran avant la réponse réseau
  let delta = currentEmoji === emoji ? -1 : (currentEmoji ? 0 : 1);
  const newMine = currentEmoji === emoji ? '' : emoji;
  bar.dataset.mine = newMine;
  total = Math.max(0, total + delta);
  totalEl.textContent = total > 0 ? total : '';
  bar.querySelectorAll('button').forEach(b => {
    const on = b.textContent.trim() === newMine;
    b.style.background = on ? 'rgba(232,148,10,0.18)' : 'none';
    b.style.border = on ? '1px solid rgba(232,148,10,0.5)' : '1px solid transparent';
    if (on) { b.style.transform = 'scale(1.25)'; setTimeout(() => { b.style.transform = ''; }, 140); }
  });

  try {
    await wzSetReaction(postId, emoji, currentEmoji);
  } catch (e) {
    // Rollback
    bar.dataset.mine = currentEmoji;
    totalEl.textContent = (total - delta) > 0 ? (total - delta) : '';
    toast('Ta réaction n\'est pas partie. Vérifie ta connexion et réessaie.', 'error');
  }
}

async function wzFetchComments(postIds) {
  if (!postIds.length) return {};
  const supa = window.supabase;
  const { data: rows } = await supa.from('wozali_commentaires').select('*').in('post_id', postIds).eq('actif', true).order('created_at', { ascending: true });
  const auteurIds = [...new Set((rows || []).map(r => r.auteur_id).filter(Boolean))];
  let aMap = {};
  if (auteurIds.length) {
    const { data: prs } = await supa.from('wozali_prestataires').select('id, user_id, nom_complet, photo_profil').in('user_id', auteurIds);
    (prs || []).forEach(p => { aMap[p.user_id] = p; });
  }
  const byPost = {};
  (rows || []).forEach(r => {
    const a = aMap[r.auteur_id] || {};
    if (!byPost[r.post_id]) byPost[r.post_id] = [];
    byPost[r.post_id].push({ id: r.id, texte: r.contenu || '', auteur: a.nom_complet || 'Utilisateur', auteurPhoto: a.photo_profil || '', auteurId: a.id || null, date: r.created_at });
  });
  return byPost;
}

async function submitPost(recordId) {
  const textarea = document.getElementById(`post-composer-${recordId}`);
  const mediaInput = document.getElementById(`post-img-${recordId}`);
  const texte = textarea?.value?.trim();
  const file  = mediaInput?.files[0];
  const isVideo = file?.type?.startsWith('video/');

  // Validation
  if (!texte && !file) { toast('Écris quelque chose ou ajoute une photo / vidéo', 'error'); return; }
  if (texte && texte.length < 3) { toast('Le texte doit faire au minimum 3 caractères', 'error'); return; }
  if (texte && texte.length > 2000) { toast('Le post est trop long (max 2000 caractères)', 'error'); return; }
  if (file && !isVideo && file.size > 5 * 1024 * 1024) { toast('L\'image est trop lourde (max 5 MB)', 'error'); return; }
  if (isVideo && file.size > 500 * 1024 * 1024) { toast('La vidéo est trop lourde (max 500 MB)', 'error'); return; }

  const btn = document.querySelector(`#posts-section-${recordId} button[onclick*="submitPost"]`);
  if (btn) { btn.textContent = '⏳'; btn.disabled = true; }

  let mediaUrl  = '';
  let mediaType = 'text';

  if (file) {
    try {
      if (isVideo) {
        if (btn) btn.textContent = '📤 Upload vidéo...';
        mediaUrl  = await uploadMediaToSupabase(file);
        mediaType = 'video';
      } else {
        if (btn) btn.textContent = '📤 Upload photo...';
        const toB64 = (f) => new Promise((resolve, reject) => {
          const r = new FileReader(); r.onload = () => resolve(r.result.split(',')[1]); r.onerror = reject; r.readAsDataURL(f);
        });
        const b64 = await toB64(file);
        const res = await fetch('/api/imgbb-proxy', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ image: b64 })
        });
        const data = await res.json();
        mediaUrl  = data?.data?.url || '';
        mediaType = 'photo';
      }
    } catch(e) {
      console.error('Upload media failed', e);
      toast('Le fichier n\'est pas passé. Vérifie ta connexion ou choisis un fichier plus léger.', 'error');
      if (btn) { btn.textContent = 'Publier'; btn.disabled = false; }
      return;
    }
  }

  // Sauvegarder dans Supabase wozali_posts (système unifié)
  try {
    const supa = window.supabase;
    if (!supa) throw new Error('Supabase non chargé');
    const { data: postData, error: postErr } = await supa.from('wozali_posts').insert({
      auteur_id:      currentUser?.id || null,
      prestataire_id: recordId,
      type:           'realisation',
      contenu:        texte || '',
      media_url:      mediaUrl || null,
      media_type:     mediaType || 'text',
      actif:          true,
    }).select('id').single();
    if (postErr) throw postErr;
    // Auto-ajouter au album Publications si l'owner publie
    if (mediaUrl && currentPrestataire?.id === recordId && postData) {
      await _addToPublicationsAlbum(mediaUrl, mediaType === 'video' ? 'video' : 'photo', postData.id || '');
      currentPrestataire.fields['Albums'] = JSON.stringify(_getAlbums()); // sync local
    }
  } catch(e) {
    console.error('[submitPost]', e);
    toast('Ta publication n\'est pas partie. Vérifie ta connexion et réessaie.', 'error');
    if (btn) { btn.textContent = 'Publier'; btn.disabled = false; }
    return;
  }

  if (textarea) textarea.value = '';
  clearPostMedia(recordId);
  if (btn) { btn.textContent = 'Publier'; btn.disabled = false; }

  await renderPostsFeed(recordId);
}

async function renderPostsFeed(recordId) {
  const feedEl = document.getElementById(`posts-feed-${recordId}`);
  if (!feedEl) return;
  feedEl.innerHTML = `<div style="text-align:center;padding:24px;color:rgba(255,255,255,0.3);font-size:13px;">⏳ Chargement...</div>`;

  // Charger depuis Supabase wozali_posts (système unifié)
  let posts = [];
  try {
    const supa = window.supabase;
    if (!supa) throw new Error('Supabase non chargé');
    const { data: rows, error: postsErr } = await supa
      .from('wozali_posts')
      .select('*')
      .eq('prestataire_id', recordId)
      .eq('actif', true)
      .order('created_at', { ascending: false })
      .limit(50);
    if (postsErr) throw postsErr;
    const postIds = (rows || []).map(r => r.id);
    const [commentsByPost, myLikes] = await Promise.all([wzFetchComments(postIds), wzFetchMyLikes(postIds)]);
    const auteurIds = [...new Set((rows || []).map(r => r.auteur_id).filter(Boolean))];
    let auteurMap = {};
    if (auteurIds.length) {
      const { data: prs } = await supa.from('wozali_prestataires').select('id, user_id, nom_complet, photo_profil').in('user_id', auteurIds);
      (prs || []).forEach(p => { auteurMap[p.user_id] = p; });
    }
    posts = (rows || []).map(r => {
      const a = auteurMap[r.auteur_id] || {};
      return {
        id:          r.id,
        texte:       r.contenu      || '',
        photo:       r.media_url    || '',
        mediaType:   r.media_type   || 'text',
        date:        r.created_at   || '',
        auteur:      a.nom_complet  || '',
        auteurPhoto: a.photo_profil || '',
        auteurId:    a.id           || null,
        likes:       r.nb_likes     || 0,
        partages:    r.nb_partages  || 0,
        ordre:       (r.ordre ?? null),
        hasLiked:    myLikes.has(r.id),
        comments:    commentsByPost[r.id] || []
      };
    });
  } catch(e) { feedEl.innerHTML = `<div style="color:rgba(255,100,100,0.6);padding:16px;font-size:13px;">Erreur de chargement</div>`; return; }

  if (posts.length === 0) {
    const isOwner = currentUser && currentPrestataire?.id === recordId;
    feedEl.innerHTML = `<div style="text-align:center;padding:32px;color:rgba(255,255,255,0.3);font-size:14px;"><div style="font-size:32px;margin-bottom:10px;">📭</div>Aucune publication pour l'instant.${isOwner ? '<br><span style="font-size:12px;">Partage ta première réalisation !</span>' : ''}</div>`;
    return;
  }

  // Trier : ordre manuel d'abord (si défini), sinon par date décroissante
  posts.sort((a, b) => {
    const ao = (a.ordre == null) ? Infinity : a.ordre;
    const bo = (b.ordre == null) ? Infinity : b.ordre;
    if (ao !== bo) return ao - bo;
    return new Date(b.date) - new Date(a.date);
  });
  window._profilPosts = window._profilPosts || {};
  window._profilPosts[recordId] = posts;
  _renderPostsFeedCards(recordId);
}

// ── Feed façon Threads/Twitter : texte seul, photo ou vidéo, tout visible directement ──
function _renderPostsFeedCards(recordId) {
  const feedEl = document.getElementById(`posts-feed-${recordId}`);
  if (!feedEl) return;
  const posts = (window._profilPosts && window._profilPosts[recordId]) || [];
  const isOwner = currentUser && currentPrestataire?.id === recordId;
  const reordering = window._pfReorder === recordId;

  const cardsHtml = posts.map((p, idx) => {
    const dateStr = new Date(p.date).toLocaleDateString('fr-FR', { day:'numeric', month:'short', year:'numeric' });
    const isVideo = p.mediaType === 'video';
    const photoSafe = encodeURI(p.photo || '');
    const initiale = (p.auteur || '?').charAt(0).toUpperCase();
    const hasLiked = !!p.hasLiked;
    const comments = p.comments || [];

    const media = p.photo
      ? (isVideo
          ? `<video src="${photoSafe}" controls playsinline preload="metadata" class="pf-card-media"></video>`
          : `<img src="${photoSafe}" loading="lazy" class="pf-card-media">`)
      : '';

    const commentsHtml = comments.length
      ? comments.map(c => {
          const cInit = (c.auteur || '?').charAt(0).toUpperCase();
          const cDate = c.date ? new Date(c.date).toLocaleDateString('fr-FR', { day:'numeric', month:'short' }) : '';
          const cPhoto = c.auteurPhoto ? `<img src="${encodeURI(c.auteurPhoto)}" class="pf-cav">` : `<div class="pf-cav pf-cav-ini">${cInit}</div>`;
          return `<div class="pf-comment">${cPhoto}<div class="pf-cbody"><div class="pf-cnom">${escapeHtml(c.auteur || '')} <span class="pf-cdate">· ${cDate}</span></div><div class="pf-ctext">${escapeHtml(c.texte || '').replace(/\n/g,'<br>')}</div></div></div>`;
        }).join('')
      : '<div class="pf-nocomment">Aucun commentaire. Sois le premier.</div>';

    const reorderCtrls = (isOwner && reordering && posts.length > 1)
      ? `<div class="pf-card-reorder">${idx > 0 ? `<button onclick="movePost('${recordId}','${p.id}',-1)" aria-label="Monter">↑</button>` : ''}${idx < posts.length - 1 ? `<button onclick="movePost('${recordId}','${p.id}',1)" aria-label="Descendre">↓</button>` : ''}</div>`
      : '';

    const authorClick = p.auteurId ? `onclick="showProfil('${p.auteurId}');showPage('profil');"` : '';

    return `<div class="pf-card">
      <div class="pf-card-head">
        <div class="pf-card-author" ${authorClick}>
          ${p.auteurPhoto ? `<img src="${encodeURI(p.auteurPhoto)}" class="pf-hav">` : `<div class="pf-hav pf-hav-ini">${initiale}</div>`}
          <div><div class="pf-nom">${escapeHtml(p.auteur || '')}</div><div class="pf-date">${dateStr}</div></div>
        </div>
        <div class="pf-card-headctrl">
          ${reorderCtrls}
          ${(isOwner && !reordering) ? `<button class="pf-delbtn" onclick="deletePost('${recordId}','${p.id}')" aria-label="Supprimer">🗑</button>` : ''}
        </div>
      </div>
      ${p.texte ? `<div class="pf-card-text">${escapeHtml(p.texte).replace(/\n/g,'<br>')}</div>` : ''}
      ${media ? `<div class="pf-card-media-wrap">${media}</div>` : ''}
      <div class="pf-card-actions">
        <button class="pf-actbtn ${hasLiked ? 'liked' : ''}" onclick="likePost('${recordId}','${p.id}')">${hasLiked ? '❤️' : '🤍'} <span>${p.likes || 0}</span></button>
        <button class="pf-actbtn" onclick="toggleCommentBox('${recordId}','${p.id}')">💬 <span>${comments.length}</span></button>
        <button class="pf-actbtn" onclick="sharePost('${recordId}','${p.id}')">➤ <span id="pf-share-${p.id}">${p.partages || 0}</span></button>
        ${(isOwner && p.photo) ? `<button class="pf-actbtn" onclick="generatePostStory('${recordId}','${p.id}')" title="Exporter en Statut WhatsApp">📤</button>` : ''}
      </div>
      <div id="comments-section-${p.id}" class="pf-comments" style="display:none;">
        ${commentsHtml}
        <div class="pf-addcomment">
          <input id="comment-input-${p.id}" placeholder="Écrire un commentaire..." onkeydown="if(event.key==='Enter')submitComment('${recordId}','${p.id}')">
          <button onclick="submitComment('${recordId}','${p.id}')" aria-label="Envoyer">➤</button>
        </div>
      </div>
    </div>`;
  }).join('');

  const showReorderBtn = isOwner && posts.length > 1;
  const toolbar = showReorderBtn
    ? `<div class="pf-toolbar">${reordering ? '<span class="pf-reorder-hint">Utilise les flèches ↑ ↓ sur chaque post</span>' : ''}<button class="pf-reorder-btn ${reordering ? 'on' : ''}" onclick="toggleReorderMode('${recordId}')">${reordering ? '✓ Terminé' : '↕ Réorganiser mes posts'}</button></div>`
    : '';
  feedEl.innerHTML = toolbar + `<div class="pf-feed-list">${cardsHtml}</div>`;
}

function toggleReorderMode(recordId) {
  window._pfReorder = (window._pfReorder === recordId) ? null : recordId;
  _renderPostsFeedCards(recordId);
}

async function movePost(recordId, postId, dir) {
  const posts = (window._profilPosts && window._profilPosts[recordId]) || [];
  const i = posts.findIndex(x => String(x.id) === String(postId));
  const j = i + dir;
  if (i < 0 || j < 0 || j >= posts.length) return;
  const tmp = posts[i]; posts[i] = posts[j]; posts[j] = tmp;
  _renderPostsFeedCards(recordId);
  const supa = window.supabase;
  if (!supa) return;
  try { await Promise.all(posts.map((p, k) => { p.ordre = k; return supa.from('wozali_posts').update({ ordre: k }).eq('id', p.id); })); } catch (e) {}
}

async function sharePost(recordId, postId) {
  const posts = (window._profilPosts && window._profilPosts[recordId]) || [];
  const p = posts.find(x => String(x.id) === String(postId));
  if (!p) return;
  // Incrémenter le compteur de partages
  const supa = window.supabase;
  try {
    if (supa) {
      await supa.rpc('wozali_post_partage', { p_post_id: postId });
      p.partages = (p.partages || 0) + 1;
      const el = document.getElementById('pf-share-' + postId);
      if (el) el.textContent = p.partages;
    }
  } catch (e) {}
  // Ouvrir le partage natif (ou WhatsApp en fallback)
  const txt = (p.texte ? p.texte + '\n\n' : '') + 'Vu sur WOZALI';
  const url = 'https://wozali.africa';
  try {
    if (navigator.share) { await navigator.share({ title: 'WOZALI', text: txt, url }); }
    else { window.open('https://wa.me/?text=' + encodeURIComponent(txt + '\n' + url), '_blank'); }
  } catch (e) {}
}

// ── SYSTÈME DE NOTIFICATIONS / ACTIVITÉ ──
function pushNotif(recordId, notif) {
  const key = `wozali_notifs_${recordId}`;
  const notifs = JSON.parse(localStorage.getItem(key) || '[]');
  notifs.unshift({ ...notif, id: Date.now().toString(), date: new Date().toISOString(), read: false });
  if (notifs.length > 100) notifs.splice(100);
  localStorage.setItem(key, JSON.stringify(notifs));
  updateNotifBadge(recordId);
}

function updateNotifBadge(recordId) {
  if (!recordId) return;
  const key = `wozali_notifs_${recordId}`;
  const notifs = JSON.parse(localStorage.getItem(key) || '[]');
  let unread = notifs.filter(n => !n.read).length;
  // Ajouter les messages du fondateur non lus depuis Supabase notifications
  try {
    const fondateur = _getFondateurMessages();
    unread += fondateur.filter(m => !m.read).length;
  } catch(e){}
  unread += (window._storyRepsUnread || 0);
  const badge = document.getElementById('notif-badge');
  if (badge) {
    if (unread > 0) {
      badge.textContent = unread > 99 ? '99+' : String(unread);
      badge.style.display = 'inline-block';
    } else {
      badge.style.display = 'none';
    }
  }
  // Même badge sur l'onglet Messages de la barre de navigation mobile
  const bntBadge = document.getElementById('bnt-messages-badge');
  if (bntBadge) {
    if (unread > 0) {
      bntBadge.textContent = unread > 99 ? '99+' : String(unread);
      bntBadge.style.display = 'flex';
    } else {
      bntBadge.style.display = 'none';
    }
  }
}

// ══ RÉPONSES AUX STORIES — conversations dans l'Activité (étape 6) ══
// Chaque personne qui répond à une story devient une conversation.
async function loadStoryReponsesConvs() {
  const host = document.getElementById('dm-more-convs');
  if (!host || !currentUser) return;
  try {
    const { data: reps } = await window.supabase
      .from('wozali_story_reponses')
      .select('*')
      .eq('vers_user_id', currentUser.id)
      .order('created_at', { ascending: false })
      .limit(200);
    if (!reps || !reps.length) { host.innerHTML = ''; window._storyRepsUnread = 0; updateNotifBadge(currentPrestataire?.id); return; }

    // Grouper par expéditeur
    const bySender = {};
    reps.forEach(r => {
      if (!bySender[r.de_user_id]) bySender[r.de_user_id] = [];
      bySender[r.de_user_id].push(r);
    });
    window._storyRepsBySender = bySender;
    window._storyRepsUnread = reps.filter(r => !r.lu).length;

    const senderIds = Object.keys(bySender);
    const { data: prs } = await window.supabase
      .from('wozali_prestataires')
      .select('id, user_id, nom_complet, metier_principal, photo_profil')
      .in('user_id', senderIds);
    const pMap = {};
    (prs || []).forEach(p => { pMap[p.user_id] = p; });
    window._storyRepsSenders = pMap;

    host.innerHTML = senderIds.map(uid => {
      const p = pMap[uid] || {};
      const msgs = bySender[uid];
      const nom = p.nom_complet || 'Utilisateur WOZALI';
      const ini = nom.charAt(0).toUpperCase();
      const nonLus = msgs.filter(m => !m.lu).length;
      const dernier = msgs[0];
      return `<div class="dm-conv-item" id="dm-conv-story-${uid}" onclick="openDmThread('story-${uid}')">
        <div class="dm-conv-avatar-link">
          <div class="dm-conv-avatar" style="${p.photo_profil ? 'overflow:hidden;padding:0;background:transparent;' : ''}">${p.photo_profil ? `<img src="${encodeURI(p.photo_profil)}" style="width:100%;height:100%;object-fit:cover;border-radius:50%;">` : ini}</div>
        </div>
        <div class="dm-conv-info">
          <div class="dm-conv-name-row">
            <span class="dm-conv-name">${escapeHtml(nom)}</span>
            <span class="dm-conv-time">${_relativeTime(dernier.created_at)}</span>
          </div>
          <div class="dm-conv-preview-row">
            <span class="dm-conv-preview">✨ ${escapeHtml((dernier.contenu || '').slice(0, 48))}</span>
            ${nonLus ? `<div class="dm-unread-badge">${nonLus}</div>` : ''}
          </div>
        </div>
      </div>`;
    }).join('');
    updateNotifBadge(currentPrestataire?.id);
  } catch(e) { console.warn('[story reps convs]', e); }
}

async function _loadStoryThread(senderUid) {
  const list = document.getElementById('dm-messages-list');
  if (!list) return;
  // V1 : thread en lecture (réponse directe dans un prochain sprint) — le
  // composer "Écrire à WOZALI" appartient au thread fondateur, on le masque.
  const composer = document.querySelector('.dm-compose-bar');
  if (composer) { composer.style.display = 'none'; composer.dataset.hiddenForStory = '1'; }
  const msgs = (window._storyRepsBySender || {})[senderUid] || [];
  const p = (window._storyRepsSenders || {})[senderUid] || {};
  const nom = p.nom_complet || 'Utilisateur WOZALI';

  // Header du thread : la personne qui a répondu, cliquable vers son profil
  const av = document.getElementById('dm-thread-avatar');
  if (av) {
    if (p.photo_profil) { av.style.overflow='hidden'; av.style.padding='0'; av.style.background='transparent'; av.innerHTML = `<img src="${encodeURI(p.photo_profil)}" style="width:100%;height:100%;object-fit:cover;border-radius:50%;">`; }
    else { av.style.overflow=''; av.style.background=''; av.innerHTML = ''; av.textContent = nom.charAt(0).toUpperCase(); }
  }
  const nameEl = document.getElementById('dm-thread-name');
  if (nameEl) nameEl.textContent = nom;
  const profileLink = document.getElementById('dm-thread-profile-link');
  if (profileLink && p.id) { profileLink.removeAttribute('target'); profileLink.removeAttribute('href'); profileLink.setAttribute('onclick', `event.preventDefault();showProfil('${p.id}');showPage('profil');`); }

  // Messages (réponses à mes stories, du plus ancien au plus récent)
  const chrono = [...msgs].reverse();
  list.innerHTML = `<div style="text-align:center;padding:10px 0 4px;color:rgba(252,224,168,0.35);font-size:11px;">✨ Réponses à tes stories</div>` +
    chrono.map(m => `
    <div style="display:flex;justify-content:flex-start;padding:4px 12px;">
      <div style="max-width:78%;background:rgba(255,255,255,0.06);border:1px solid rgba(255,255,255,0.08);border-radius:14px 14px 14px 4px;padding:10px 14px;">
        <div style="font-size:14px;color:#FCE0A8;line-height:1.5;">${escapeHtml(m.contenu || '')}</div>
        <div style="font-size:10px;color:rgba(252,224,168,0.35);margin-top:4px;">${_relativeTime(m.created_at)}</div>
      </div>
    </div>`).join('') +
    (p.id ? `<div style="text-align:center;padding:14px 0;"><button onclick="showProfil('${p.id}');showPage('profil');" style="background:rgba(232,148,10,0.12);color:#E8940A;border:1px solid rgba(232,148,10,0.3);border-radius:100px;padding:9px 20px;font-size:13px;font-weight:700;cursor:pointer;font-family:inherit;">Voir son profil →</button></div>` : '');
  list.scrollTop = list.scrollHeight;

  // Marquer comme lues + rafraîchir badges
  const nonLuIds = msgs.filter(m => !m.lu).map(m => m.id);
  if (nonLuIds.length) {
    try {
      await window.supabase.from('wozali_story_reponses').update({ lu: true }).in('id', nonLuIds);
      msgs.forEach(m => { m.lu = true; });
      window._storyRepsUnread = Math.max(0, (window._storyRepsUnread || 0) - nonLuIds.length);
      const convBadge = document.querySelector('#dm-conv-story-' + senderUid + ' .dm-unread-badge');
      if (convBadge) convBadge.remove();
      updateNotifBadge(currentPrestataire?.id);
    } catch(e) {}
  }
}

// ══ BOÎTE DU FONDATEUR — Messages de Schealtiel + demandes clients ══
function _getFondateurMessages() {
  const raw = window.currentPrestataire?.fields?.['Notifications'];
  if (!raw) return [];
  let arr = [];
  try { arr = typeof raw === 'string' ? JSON.parse(raw) : raw; } catch(e) { return []; }
  if (!Array.isArray(arr)) return [];
  // Affiche les messages de Schealtiel ET les demandes clients pushées
  // par les endpoints widgets (réservations, devis, commandes, RDV…).
  const now = new Date();
  return arr.filter(m => m && (m.type === 'message_fondateur' || m.type === 'demande_client')
    && (!m.created_at || new Date(m.created_at) <= now));
}

function renderFondateurInbox() {
  const block = document.getElementById('fondateur-inbox-block');
  if (!block || !window.currentPrestataire) return;
  const messages = _getFondateurMessages();
  if (messages.length === 0) { block.style.display = 'none'; block.innerHTML = ''; return; }
  block.style.display = 'block';
  const unreadCount = messages.filter(m => !m.read).length;
  // Trier : non-lus d'abord, puis par date desc.
  messages.sort((a, b) => {
    const ar = a.read ? 1 : 0, br = b.read ? 1 : 0;
    if (ar !== br) return ar - br;
    return new Date(b.created_at || 0) - new Date(a.created_at || 0);
  });
  block.innerHTML = `
    <div style="background:linear-gradient(135deg,rgba(232,148,10,0.08) 0%,rgba(232,148,10,0.02) 100%);border:1px solid rgba(232,148,10,0.25);border-radius:16px;padding:18px 20px;">
      <div style="display:flex;align-items:center;gap:12px;margin-bottom:18px;">
        <div style="width:46px;height:46px;border-radius:50%;background:#E8940A;color:#14100A;display:flex;align-items:center;justify-content:center;font-weight:900;font-size:22px;font-family:'DM Serif Display',serif;flex-shrink:0;">📬</div>
        <div style="flex:1;">
          <div style="font-family:'DM Serif Display',serif;font-size:18px;font-weight:800;color:#FCE0A8;">Boîte WOZALI</div>
          <div style="font-size:12px;color:rgba(252, 224, 168,0.55);">Messages du fondateur + demandes clients${unreadCount > 0 ? ` · <span style="color:#E8940A;font-weight:700;">${unreadCount} non-lu${unreadCount > 1 ? 's' : ''}</span>` : ''}</div>
        </div>
        
      </div>
      <div style="display:flex;flex-direction:column;gap:12px;">
        ${messages.map(m => {
          const dateStr = new Date(m.created_at || Date.now()).toLocaleDateString('fr-FR', { day:'numeric', month:'short', hour:'2-digit', minute:'2-digit' });
          const unreadDot = !m.read ? '<span style="display:inline-block;width:8px;height:8px;border-radius:50%;background:#E8940A;margin-right:6px;"></span>' : '';
          const isDemande = m.type === 'demande_client';
          const fromTxt = isDemande ? 'Demande client · WOZALI' : ('— ' + (m.from || 'Le fondateur WOZALI'));
          const sectionTarget = (m.action_url && m.action_url.indexOf('section=') >= 0)
            ? (m.action_url.split('section=')[1] || '').replace(/['"]/g,'') : '';
          return `<div onclick="_handleFondateurMessageClick('${m.id}','${sectionTarget}')" style="background:${m.read ? 'rgba(252, 224, 168,0.04)' : 'rgba(232,148,10,0.08)'};border:1px solid ${m.read ? 'rgba(252, 224, 168,0.08)' : 'rgba(232,148,10,0.25)'};border-radius:12px;padding:14px 16px;cursor:pointer;">
            <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:10px;margin-bottom:8px;">
              <div style="font-weight:700;font-size:14px;color:#FCE0A8;">${unreadDot}${(m.title || 'Message').replace(/</g,'&lt;')}</div>
              <div style="font-size:11px;color:rgba(252, 224, 168,0.45);white-space:nowrap;">${dateStr}</div>
            </div>
            <div style="font-size:13px;line-height:1.65;color:rgba(252, 224, 168,0.78);white-space:pre-line;">${(m.body || '').replace(/</g,'&lt;')}</div>
            <div style="margin-top:10px;font-size:11px;color:${isDemande ? 'rgba(255,200,80,0.85)' : 'rgba(232,148,10,0.7)'};font-style:italic;">${fromTxt.replace(/</g,'&lt;')}</div>
          </div>`;
        }).join('')}
      </div>
    </div>`;
}

async function markFondateurMessageRead(msgId) {
  if (!window.currentPrestataire) return;
  const raw = window.currentPrestataire.fields?.['Notifications'];
  let arr = [];
  try { arr = typeof raw === 'string' ? JSON.parse(raw) : (raw || []); } catch(e) { return; }
  if (!Array.isArray(arr)) return;
  let changed = false;
  arr = arr.map(m => {
    if (m && m.id === msgId && !m.read) { changed = true; return { ...m, read: true }; }
    return m;
  });
  if (!changed) return;
  // Update Supabase + state local
  try {
    if (window.supaPrest) {
      await window.supaPrest.update(window.currentPrestataire.id, { 'Notifications': arr });
    }
    window.currentPrestataire.fields['Notifications'] = arr;
    updateNotifBadge(window.currentPrestataire.id);
  } catch(e) { console.warn('[mark fondateur read]', e); }
}

// Click handler unique pour les cartes de la Boîte du Fondateur :
// - marque le message comme lu
// - bascule vers la section dashboard liée si action_url=#dashboard?section=...
function _handleFondateurMessageClick(msgId, sectionTarget) {
  if (sectionTarget && typeof showDashSection === 'function') {
    try { showDashSection(sectionTarget); } catch(_) {}
  }
  if (typeof markFondateurMessageRead === 'function') markFondateurMessageRead(msgId);
}

// ══════════════════════════════════════════
// CHAT WOZALI — Widget "Écrire à WOZALI"
// IA auto-reply + escalade fondateur
// ══════════════════════════════════════════

function openWozaliChat() {
  const compose = document.getElementById('wozali-chat-compose');
  const response = document.getElementById('wozali-chat-response');
  if (!compose) return;
  compose.style.display = 'block';
  if (response) response.style.display = 'none';
  const input = document.getElementById('wozali-chat-input');
  if (input) { input.value = ''; setTimeout(() => input.focus(), 50); }
}

function closeWozaliChat() {
  const compose = document.getElementById('wozali-chat-compose');
  if (compose) compose.style.display = 'none';
}

async function sendWozaliChatMessage() {
  const input = document.getElementById('wozali-chat-input');
  const btn = document.getElementById('wozali-chat-send-btn');
  const responseEl = document.getElementById('wozali-chat-response');
  if (!input || !btn || !responseEl) return;

  const message = input.value.trim();
  if (!message) { input.focus(); return; }

  // UI loading
  btn.disabled = true;
  btn.textContent = '⏳ Envoi...';

  try {
    const resp = await wozaliFetch('/api/wozali-pay/chat-wozali-send', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ message }),
    });
    const data = await resp.json();

    // Cacher la zone de saisie
    closeWozaliChat();

    // Afficher la réponse
    responseEl.style.display = 'block';

    if (data.ok && data.reponse) {
      // Réponse IA disponible
      responseEl.innerHTML = `
        <div style="background:linear-gradient(135deg,rgba(232,148,10,0.08),rgba(232,148,10,0.02));border:1.5px solid rgba(232,148,10,0.25);border-radius:16px;padding:18px 20px;">
          <div style="display:flex;align-items:flex-start;gap:10px;margin-bottom:12px;">
            <div style="width:36px;height:36px;border-radius:50%;background:#E8940A;color:#14100A;display:flex;align-items:center;justify-content:center;font-size:18px;font-family:'DM Serif Display',serif;font-weight:900;flex-shrink:0;">S</div>
            <div style="flex:1;">
              <div style="font-family:'DM Serif Display',serif;font-size:15px;font-weight:800;color:#FCE0A8;">Le fondateur</div>
              <div style="font-size:11px;color:rgba(252,224,168,0.45);font-family:'Geist Mono',monospace;letter-spacing:1px;">Fondateur WOZALI</div>
            </div>
          </div>
          <div style="font-size:14px;line-height:1.7;color:rgba(252,224,168,0.88);white-space:pre-line;">"${escapeHtml(data.reponse)}"</div>
          <div style="margin-top:8px;font-size:12px;color:rgba(252,224,168,0.4);font-style:italic;font-family:'Geist Mono',monospace;">Le fondateur WOZALI</div>
          <div style="margin-top:14px;padding-top:12px;border-top:1px solid rgba(232,148,10,0.12);display:flex;gap:10px;flex-wrap:wrap;">
            <button onclick="openWozaliChat()" style="background:transparent;border:1px solid rgba(232,148,10,0.35);color:#E8940A;padding:8px 16px;border-radius:100px;font-size:13px;font-weight:700;cursor:pointer;font-family:inherit;">✉️ Autre question</button>
            <button onclick="toggleWozaliHistory()" style="background:transparent;border:1px solid rgba(252,224,168,0.12);color:rgba(252,224,168,0.5);padding:8px 14px;border-radius:100px;font-size:12px;font-weight:600;cursor:pointer;font-family:inherit;">📜 Voir l'historique</button>
          </div>
        </div>`;
    } else {
      // Escalade fondateur — message neutre
      const msgAffiche = data.message_affiche || 'Message envoyé — nous reviendrons vers toi bientôt.';
      responseEl.innerHTML = `
        <div style="background:rgba(232,148,10,0.05);border:1px solid rgba(232,148,10,0.2);border-radius:16px;padding:18px 20px;">
          <div style="display:flex;align-items:center;gap:10px;margin-bottom:8px;">
            <span style="font-size:24px;">✅</span>
            <div style="font-family:'DM Serif Display',serif;font-size:15px;font-weight:800;color:#FCE0A8;">Message envoyé</div>
          </div>
          <div style="font-size:14px;color:rgba(252,224,168,0.75);">${escapeHtml(msgAffiche)}</div>
          <button onclick="openWozaliChat()" style="margin-top:12px;background:transparent;border:1px solid rgba(232,148,10,0.35);color:#E8940A;padding:8px 16px;border-radius:100px;font-size:13px;font-weight:700;cursor:pointer;font-family:inherit;">✉️ Envoyer un autre message</button>
        </div>`;
    }
  } catch(e) {
    console.error('[chat-wozali] send error:', e);
    btn.disabled = false;
    btn.textContent = 'Envoyer ➤';
    // Toast d'erreur discret
    if (typeof toast === 'function') toast('Ça a calé. Réessaie dans 2 secondes.', 'error');
    return;
  }

  btn.disabled = false;
  btn.textContent = 'Envoyer ➤';
}

// ══════════════════════════════════════════
// MESSAGERIE DM — Interface 2 colonnes
// ══════════════════════════════════════════

function initDmInterface() {
  // Avatar initiale barre de compose
  const composeAvatar = document.getElementById('dm-compose-avatar');
  if (composeAvatar && window.currentPrestataire) {
    const name = window.currentPrestataire.fields?.['Prénom'] || window.currentPrestataire.fields?.['Nom'] || '?';
    composeAvatar.textContent = name.charAt(0).toUpperCase();
  }

  _initDmResize();

  // Charger le profil fondateur en arrière-plan pour personnaliser l'affichage
  _loadFondateurProfile();

  // Sur desktop : ouvrir le thread WOZALI d'office
  if (window.innerWidth > 768) openDmThread('wozali');
}

async function _loadFondateurProfile() {
  if (window._fondateurProfileLoaded) return window._fondateurProfile;
  window._fondateurProfileLoaded = true;

  // Cache local : affichage instantané (nom + photo) pendant que le réseau charge en arrière-plan
  try {
    const cached = JSON.parse(localStorage.getItem('wozali_fondateur_cache') || 'null');
    if (cached) _applyFondateurProfileToUI(cached);
  } catch(e) {}

  try {
    if (!window.supaPrest) return null;
    const r = await window.supaPrest.findByEmail('schealtiellawson@gmail.com');
    if (!r) return null;
    window._fondateurProfile = r;
    _applyFondateurProfileToUI(r);
    try { localStorage.setItem('wozali_fondateur_cache', JSON.stringify(r)); } catch(e) {}
    return r;
  } catch(e) {
    console.warn('[fondateur profile]', e);
    return null;
  }
}

function _applyFondateurProfileToUI(profil) {
  if (!profil) return;
  const f = profil.fields || {};
  // Nom affiché : toujours le nom public choisi (Nom complet), jamais le nom de famille privé
  const nomAffiche = f['Nom complet'] || f['Prénom'] || 'Schealtiel';
  const initial = nomAffiche.charAt(0).toUpperCase();
  const photoUrl = _wPhotoUrl(f['Photo de profil']);
  const recordId = profil.id;

  window._fondateurNom = nomAffiche;
  window._fondateurInitial = initial;
  window._fondateurRecordId = recordId;
  window._fondateurPhotoUrl = photoUrl;

  const setAvatar = (el) => {
    if (!el) return;
    if (photoUrl) {
      el.style.overflow = 'hidden';
      el.style.padding = '0';
      el.style.background = 'transparent';
      el.innerHTML = `<img src="${photoUrl}" style="width:100%;height:100%;object-fit:cover;border-radius:50%;" onerror="this.parentNode.style.background='linear-gradient(135deg,#E8940A,#b86a00)';this.parentNode.innerHTML='${initial}';" />`;
    } else {
      el.textContent = initial;
    }
  };

  // Navigation interne vers le profil (l'ancien lien externe /schealtiel n'a jamais existé → 404,
  // et un slug reconstruit côté client peut ne pas correspondre à Airtable côté serveur).
  // showProfil(id) est le même mécanisme déjà utilisé partout ailleurs dans l'app, fiable à 100%.
  const goToProfil = `event.preventDefault();showProfil('${recordId}');showPage('profil');`;
  ['dm-wozali-avatar-link', 'dm-thread-profile-link', 'dm-profile-btn-link'].forEach(id => {
    const el = document.getElementById(id);
    if (el) { el.removeAttribute('target'); el.setAttribute('onclick', goToProfil); }
  });
  document.querySelectorAll('#dm-conv-wozali .dm-conv-name').forEach(el => {
    el.removeAttribute('target');
    el.setAttribute('onclick', goToProfil);
  });

  // Liste conversations : avatar + nom + lien
  const convAvatar = document.querySelector('#dm-conv-wozali .dm-conv-avatar');
  setAvatar(convAvatar);
  document.querySelectorAll('#dm-conv-wozali .dm-conv-name').forEach(el => el.textContent = nomAffiche);

  // Thread header : avatar + nom + liens
  setAvatar(document.getElementById('dm-thread-avatar'));
  const threadName = document.getElementById('dm-thread-name');
  if (threadName) threadName.textContent = nomAffiche;

  // Mettre à jour les messages déjà affichés pour refléter le vrai nom
  if (document.getElementById('dm-messages-list')?.children.length > 1) {
    loadDmMessages('wozali');
  }
}

function _initDmResize() {
  const handle = document.getElementById('dm-resize-handle');
  const col    = document.getElementById('dm-col-left');
  if (!handle || !col) return;
  // Éviter double-init
  if (handle._dmResizeInit) return;
  handle._dmResizeInit = true;

  let dragging = false, startX = 0, startW = 0;

  handle.addEventListener('mousedown', function(e) {
    dragging = true; startX = e.clientX; startW = col.offsetWidth;
    handle.classList.add('dragging');
    document.body.style.cursor = 'col-resize';
    document.body.style.userSelect = 'none';
    e.preventDefault();
  });
  document.addEventListener('mousemove', function(e) {
    if (!dragging) return;
    col.style.width = Math.max(180, Math.min(440, startW + (e.clientX - startX))) + 'px';
  });
  document.addEventListener('mouseup', function() {
    if (!dragging) return;
    dragging = false;
    handle.classList.remove('dragging');
    document.body.style.cursor = '';
    document.body.style.userSelect = '';
  });
}

function openDmThread(threadId) {
  document.querySelectorAll('.dm-conv-item').forEach(el => el.classList.remove('active'));
  const convItem = document.getElementById('dm-conv-' + threadId);
  if (convItem) convItem.classList.add('active');

  if (window.innerWidth <= 768) {
    document.getElementById('dm-col-left')?.classList.add('dm-thread-open');
    document.getElementById('dm-thread-panel')?.classList.add('dm-thread-open');
  }

  const emptyState   = document.getElementById('dm-empty-state');
  const threadContent = document.getElementById('dm-thread-content');
  if (emptyState) emptyState.style.display = 'none';
  if (threadContent) threadContent.style.display = 'flex';

  loadDmMessages(threadId);
}

function closeDmThread() {
  document.getElementById('dm-col-left')?.classList.remove('dm-thread-open');
  document.getElementById('dm-thread-panel')?.classList.remove('dm-thread-open');
}

async function loadDmMessages(threadId) {
  const list = document.getElementById('dm-messages-list');
  if (!list) return;

  if (String(threadId).startsWith('story-')) { return _loadStoryThread(threadId.slice(6)); }
  if (threadId !== 'wozali') {
    list.innerHTML = '<div style="text-align:center;padding:24px;color:rgba(252,224,168,.3);font-size:13px;font-family:\'Geist\',sans-serif;">Bientôt disponible.</div>';
    return;
  }
  // Thread fondateur : restaurer le header + le composer (un thread story a pu les modifier)
  try { if (window._fondateurNom) _applyFondateurProfileToUI({ id: window._fondateurRecordId, fields: { 'Nom complet': window._fondateurNom, 'Photo de profil': window._fondateurPhotoUrl } }); } catch(e){}
  const composerW = document.querySelector('[data-hidden-for-story="1"]');
  if (composerW) { composerW.style.display = ''; delete composerW.dataset.hiddenForStory; }

  const senderNom     = window._fondateurNom     || 'Schealtiel';
  const senderInitial = window._fondateurInitial || 'S';
  const senderPhoto   = window._fondateurPhotoUrl || '';
  const senderRecordId = window._fondateurRecordId || '';

  // Welcome sequence from Notifications JSON
  const welcomeMsgs = _getFondateurMessages();

  // Chat history from API (user replies + fondateur responses)
  let chatItems = [];
  try {
    const r = await wozaliFetch('/api/wozali-pay/chat-wozali-history');
    if (r && r.ok) {
      const data = await r.json();
      chatItems = data.messages || [];
    }
  } catch(e) {
    console.warn('[dm] history fetch failed:', e);
  }

  // Build unified display items sorted chronologically
  const displayItems = [];
  welcomeMsgs.forEach(m => {
    displayItems.push({
      kind: 'welcome',
      at: m.created_at ? new Date(m.created_at) : new Date(0),
      id: m.id,
      read: m.read,
      title: m.title,
      body: m.body,
    });
  });
  chatItems.forEach(m => {
    const at = new Date(m.created_at);
    displayItems.push({ kind: 'user_sent', at, body: m.message });
    if (m.reponse) {
      displayItems.push({ kind: 'fondateur_reply', at: new Date(m.updated_at || m.created_at), body: m.reponse });
    } else if (m.en_attente) {
      displayItems.push({ kind: 'pending', at: new Date(m.updated_at || m.created_at) });
    }
  });
  displayItems.sort((a, b) => a.at - b.at);

  let html = '<div class="dm-date-sep"><div class="dm-date-sep-line"></div><span class="dm-date-sep-label">MESSAGES</span><div class="dm-date-sep-line"></div></div>';

  if (displayItems.length === 0) {
    html += _dmBubbleIn(senderNom, senderInitial, 'Bienvenue sur WOZALI ! 👋\n\nTon profil est maintenant en ligne. Écris-moi si tu as des questions.', '', null, senderPhoto, senderRecordId);
  } else {
    displayItems.forEach((item, i) => {
      const dateStr = item.at.getTime() > 0
        ? item.at.toLocaleDateString('fr-FR', { day:'numeric', month:'short', hour:'2-digit', minute:'2-digit' })
        : '';
      if (item.kind === 'welcome') {
        const isLast   = i === displayItems.length - 1;
        const isUnread = !item.read && isLast;
        // Statut affiché : "Non lu" tant que pas ouvert, "Vu" une fois lu (au lieu de disparaître)
        const status   = isUnread ? 'unread' : (item.read ? 'seen' : null);
        const title    = item.title ? `<strong>${item.title.replace(/</g,'&lt;')}</strong>\n` : '';
        const body     = (item.body || '').replace(/</g,'&lt;');
        html += _dmBubbleIn(senderNom, senderInitial, title + body, dateStr, status, senderPhoto, senderRecordId);
        if (isUnread) markFondateurMessageRead(item.id);
      } else if (item.kind === 'user_sent') {
        html += _dmBubbleOut(item.body, dateStr);
      } else if (item.kind === 'fondateur_reply') {
        html += _dmBubbleIn(senderNom, senderInitial, item.body.replace(/</g,'&lt;'), dateStr, null, senderPhoto, senderRecordId);
      } else if (item.kind === 'pending') {
        html += `<div style="text-align:center;padding:8px 0 4px;font-style:italic;font-size:11px;color:rgba(252,224,168,0.3);font-family:'Geist',sans-serif;">Message envoyé, en attente de réponse...</div>`;
      }
    });
  }

  list.innerHTML = html;
  setTimeout(() => { list.scrollTop = list.scrollHeight; }, 60);

  // Update badge + preview
  const unread = welcomeMsgs.filter(m => !m.read).length;
  const badge  = document.getElementById('dm-wozali-badge');
  if (badge) { badge.style.display = unread > 0 ? 'flex' : 'none'; badge.textContent = String(unread); }
  document.getElementById('dm-conv-wozali')?.classList.toggle('unread', unread > 0);
  if (displayItems.length > 0) {
    const last = displayItems[displayItems.length - 1];
    const previewText = last.body || last.title || (last.kind === 'pending' ? 'En attente de réponse...' : '');
    const preview = document.getElementById('dm-wozali-preview');
    if (preview && previewText) preview.textContent = previewText.slice(0, 42) + (previewText.length > 42 ? '…' : '');
    const timeEl = document.getElementById('dm-wozali-time');
    if (timeEl && last.at.getTime() > 0) {
      timeEl.textContent = last.at.toLocaleTimeString('fr-FR', { hour:'2-digit', minute:'2-digit' });
    }
  }
}

function _dmBubbleIn(senderName, initial, bodyHtml, timeStr, status, photoUrl, recordId) {
  // status : 'unread' (non lu) | 'seen' (vu) | null (pas de statut à afficher)
  const isUnread = status === 'unread';
  let statusTag = '';
  if (status === 'unread') {
    statusTag = '<div class="dm-unread-label"><div class="dm-unread-dot"></div><span class="dm-unread-text">Non lu</span></div>';
  } else if (status === 'seen') {
    statusTag = '<div class="dm-seen-label"><span class="dm-seen-check">✓</span><span class="dm-seen-text">Vu</span></div>';
  }
  // Avatar : photo réelle si dispo, sinon initiale en repli. Cliquable vers le profil
  // via navigation interne (showProfil par ID), pas un lien externe reconstruit qui peut 404.
  const avatarInner = photoUrl
    ? `<img src="${photoUrl}" alt="${senderName}" onerror="this.parentNode.textContent='${initial}';this.parentNode.classList.add('fallback');" />`
    : initial;
  const avatarHtml = recordId
    ? `<a class="dm-msg-avatar-sm${photoUrl ? '' : ' fallback'}" href="#" onclick="event.preventDefault();showProfil('${recordId}');showPage('profil');" title="Voir le profil">${avatarInner}</a>`
    : `<div class="dm-msg-avatar-sm${photoUrl ? '' : ' fallback'}">${avatarInner}</div>`;
  return `<div class="dm-msg-in">
    ${avatarHtml}
    <div class="dm-msg-in-body">
      ${timeStr ? `<div class="dm-msg-time">${senderName} · ${timeStr}</div>` : ''}
      <div class="dm-bubble-in${isUnread ? ' unread' : ''}" style="white-space:pre-line;">${bodyHtml}</div>
      ${statusTag}
    </div>
  </div>`;
}

function _dmBubbleOut(bodyText, timeStr) {
  return `<div class="dm-msg-out">
    <div class="dm-msg-out-body">
      ${timeStr ? `<div class="dm-msg-time" style="text-align:right;">${timeStr}</div>` : ''}
      <div class="dm-bubble-out">${bodyText.replace(/</g,'&lt;')}</div>
    </div>
  </div>`;
}

async function sendDmMessage() {
  const input   = document.getElementById('wozali-chat-input');
  const sendBtn = document.getElementById('dm-send-btn');
  const list    = document.getElementById('dm-messages-list');
  if (!input || !sendBtn || !list) return;

  const message = input.value.trim();
  if (!message) { input.focus(); return; }

  const nowStr = new Date().toLocaleTimeString('fr-FR', { hour:'2-digit', minute:'2-digit' });
  const outWrap = document.createElement('div');
  outWrap.innerHTML = _dmBubbleOut(message, nowStr);
  list.appendChild(outWrap.firstElementChild);
  list.scrollTop = list.scrollHeight;

  input.value = ''; input.style.height = 'auto';
  sendBtn.disabled = true;

  try {
    await wozaliFetch('/api/wozali-pay/chat-wozali-send', {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ message }),
    });
  } catch(e) {
    console.error('[dm send]', e);
  }

  sendBtn.disabled = false; input.focus();
}

let _wozaliHistoryVisible = false;

async function toggleWozaliHistory() {
  const historyEl = document.getElementById('wozali-chat-history');
  const historyList = document.getElementById('wozali-chat-history-list');
  const btn = document.getElementById('wozali-chat-history-btn');
  if (!historyEl || !historyList) return;

  _wozaliHistoryVisible = !_wozaliHistoryVisible;
  historyEl.style.display = _wozaliHistoryVisible ? 'block' : 'none';

  if (btn) {
    btn.textContent = _wozaliHistoryVisible ? '📜 Masquer' : '📜 Historique';
  }

  if (!_wozaliHistoryVisible) return;

  // Charger l'historique
  historyList.innerHTML = '<div style="text-align:center;padding:24px;color:rgba(252,224,168,0.4);font-size:13px;">⏳ Chargement...</div>';

  try {
    const resp = await wozaliFetch('/api/wozali-pay/chat-wozali-history');
    const data = await resp.json();

    if (!data.ok || !data.messages?.length) {
      historyList.innerHTML = '<div style="text-align:center;padding:24px;color:rgba(252,224,168,0.35);font-size:13px;">Pas encore d\'échange avec WOZALI.</div>';
      return;
    }

    historyList.innerHTML = data.messages.map(m => {
      const dateStr = new Date(m.created_at).toLocaleDateString('fr-FR', { day:'numeric', month:'short', hour:'2-digit', minute:'2-digit' });
      const reponse = m.reponse;
      const enAttente = m.en_attente;

      return `<div style="margin-bottom:16px;">
        <!-- Message prestataire -->
        <div style="display:flex;justify-content:flex-end;margin-bottom:6px;">
          <div style="max-width:85%;background:rgba(232,148,10,0.12);border:1px solid rgba(232,148,10,0.2);border-radius:14px 14px 4px 14px;padding:10px 14px;">
            <div style="font-size:13px;color:#FCE0A8;line-height:1.6;white-space:pre-line;">${escapeHtml(m.message)}</div>
            <div style="font-size:10px;color:rgba(252,224,168,0.35);margin-top:5px;text-align:right;">${dateStr}</div>
          </div>
        </div>
        <!-- Réponse Schealtiel -->
        <div style="display:flex;gap:8px;align-items:flex-start;">
          <div style="width:28px;height:28px;border-radius:50%;background:#E8940A;color:#14100A;display:flex;align-items:center;justify-content:center;font-size:14px;font-family:'DM Serif Display',serif;font-weight:900;flex-shrink:0;margin-top:2px;">S</div>
          <div style="max-width:85%;background:rgba(252,224,168,0.04);border:1px solid rgba(252,224,168,0.1);border-radius:4px 14px 14px 14px;padding:10px 14px;">
            ${reponse
              ? `<div style="font-size:13px;color:rgba(252,224,168,0.82);line-height:1.6;white-space:pre-line;">"${escapeHtml(reponse)}"</div><div style="font-size:10px;color:rgba(252,224,168,0.3);margin-top:5px;font-style:italic;font-family:'Geist Mono',monospace;">Le fondateur WOZALI</div>`
              : enAttente
                ? `<div style="font-size:12px;color:rgba(232,148,10,0.6);font-style:italic;">⏳ En cours de traitement…</div>`
                : `<div style="font-size:12px;color:rgba(252,224,168,0.35);font-style:italic;">—</div>`
            }
          </div>
        </div>
      </div>`;
    }).join('');
  } catch(e) {
    console.error('[chat-wozali] history error:', e);
    historyList.innerHTML = '<div style="text-align:center;padding:16px;color:rgba(248,113,113,0.7);font-size:13px;">Erreur de chargement. Réessaie.</div>';
  }
}

