let _ambassadeurData = null;

async function checkAmbassadeurForDashboard(session) {
  try {
    if (!session) return;
    const { data, error } = await supa
      .from('wozali_ambassadeurs')
      .select('id, statut, code_affiliation, tiktok_username, tiktok_followers')
      .eq('user_id', session.user.id)
      .eq('statut', 'valide')
      .maybeSingle();
    if (error || !data) return;
    _ambassadeurData = data;
    const grp = document.getElementById('dash-ambassadeur-group');
    if (grp) grp.style.display = 'block';
  } catch (e) { console.error('[ambassadeur-check]', e); }
}

// ── Chargement section ambassadeur (user validé) ──
async function loadAmbassadeurSection() {
  if (!_ambassadeurData) {
    // Tenter un rechargement au cas où la session vient de s'initialiser
    const { data: { session } } = await supa.auth.getSession();
    if (session) await checkAmbassadeurForDashboard(session);
    if (!_ambassadeurData) {
      document.getElementById('amb-lien-display').textContent = 'Espace non disponible.';
      return;
    }
  }

  const code = _ambassadeurData.code_affiliation || '';
  const lien = code ? `https://wozali.africa/?ref=${code}` : 'Code en cours de génération...';

  // Afficher le lien
  const lienEl = document.getElementById('amb-lien-display');
  if (lienEl) lienEl.textContent = lien;

  // Charger les stats depuis wozali_prestataires
  if (code) {
    try {
      const { data: inscrits } = await supa
        .from('wozali_prestataires')
        .select('id, abonnement', { count: 'exact' })
        .eq('parrain_code', code);

      const total = inscrits ? inscrits.length : 0;
      const pro = inscrits ? inscrits.filter(p => p.abonnement === 'Pro').length : 0;
      const commission = pro * 1000;

      const el = (id, val) => { const e = document.getElementById(id); if (e) e.textContent = val; };
      el('amb-stat-inscrits', total);
      el('amb-stat-pro', pro);
      el('amb-stat-commission', pro > 0 ? _formatAmbFcfa(commission) : '0');
    } catch (e) { console.error('[amb-stats]', e); }
  }

  // Rendu immédiat de la grille formation (sans attendre Supabase)
  _renderAmbassadeurDocsGrid();
  // Puis charger les statuts réels et re-rendre
  try {
    await loadAmbassadeurDocumentReads();
    _renderAmbassadeurDocsGrid();
  } catch (e) { /* grille reste en mode non-lu */ }

  // Re-render lucide icons
  if (window.lucide) lucide.createIcons();
}

function _formatAmbFcfa(n) {
  if (n >= 1000000) return (n / 1000000).toFixed(1).replace('.0', '') + 'M';
  if (n >= 1000) return n.toLocaleString('fr-FR').replace(/\s/g, ' ');
  return String(n);
}

function copierLienAmbassadeur() {
  const lienEl = document.getElementById('amb-lien-display');
  const lien = lienEl ? lienEl.textContent.trim() : '';
  if (!lien || lien === 'Chargement...' || lien === 'Code en cours de génération...') return;
  navigator.clipboard.writeText(lien).then(() => {
    toast('Lien copié !', 'success');
  }).catch(() => {
    toast('Copie impossible. Sélectionne le lien manuellement.', 'error');
  });
}

function partagerAmbassadeurWhatsApp() {
  const lienEl = document.getElementById('amb-lien-display');
  const lien = lienEl ? lienEl.textContent.trim() : '';
  if (!lien || lien === 'Chargement...') return;
  const texte = encodeURIComponent(
    `Je suis ambassadeur WOZALI - la plateforme qui rend visible les pros qui travaillent vraiment.\n\nInscris-toi via mon lien : ${lien}\n\nTon profil sort en premier quand un client cherche ton métier.`
  );
  window.open(`https://wa.me/?text=${texte}`, '_blank');
}

// ── Admin : chargement liste ambassadeurs ──
let _ambassadeursCache = [];

async function loadAdminAmbassadeurs() {
  if (!_isAdminDash) return;
  const listEl = document.getElementById('amb-list');
  if (listEl) listEl.innerHTML = '<div style="text-align:center;padding:40px;color:var(--gris);">Chargement...</div>';

  try {
    const { data, error } = await supa
      .from('wozali_ambassadeurs')
      .select('*')
      .order('created_at', { ascending: false });

    if (error) { toast('La liste n\'a pas chargé. Recharge la page.', 'error'); return; }
    _ambassadeursCache = data || [];
    _renderAmbassadeurs(_ambassadeursCache);
    _renderAmbassadeursKpi(_ambassadeursCache);
  } catch (e) { console.error('[admin-amb]', e); toast('Ça n\'a pas marché. Réessaie dans un instant.', 'error'); }
}

function _renderAmbassadeursKpi(list) {
  const set = (id, val) => { const e = document.getElementById(id); if (e) e.textContent = val; };
  set('amb-kpi-total', list.length);
  set('amb-kpi-attente', list.filter(a => a.statut === 'en_attente').length);
  set('amb-kpi-valide', list.filter(a => a.statut === 'valide').length);
  set('amb-kpi-refuse', list.filter(a => a.statut === 'refuse').length);
}

function filterAmbassadeurs() {
  const statut = (document.getElementById('amb-filter-statut') || {}).value || '';
  const search = ((document.getElementById('amb-filter-search') || {}).value || '').toLowerCase();
  const filtered = _ambassadeursCache.filter(a => {
    if (statut && a.statut !== statut) return false;
    if (search && !(
      (a.tiktok_username || '').toLowerCase().includes(search) ||
      (a.instagram_username || '').toLowerCase().includes(search) ||
      (a.code_affiliation || '').toLowerCase().includes(search)
    )) return false;
    return true;
  });
  _renderAmbassadeurs(filtered);
}

function _renderAmbassadeurs(list) {
  const el = document.getElementById('amb-list');
  if (!el) return;
  if (!list.length) {
    el.innerHTML = '<div style="text-align:center;padding:40px;color:var(--gris);">Aucune candidature trouvée.</div>';
    return;
  }

  const statutBadge = (s) => {
    const map = { en_attente: ['#FCE0A8', 'En attente'], valide: ['#E8940A', 'Validé'], refuse: ['#ef4444', 'Refusé'] };
    const [color, label] = map[s] || ['#999', s];
    return `<span style="font-size:11px;font-weight:700;color:${color};background:${color}22;padding:3px 10px;border-radius:100px;">${label}</span>`;
  };

  el.innerHTML = list.map(a => `
    <div style="background:rgba(232,148,10,.04);border:1px solid rgba(232,148,10,.12);border-radius:14px;padding:18px;display:flex;align-items:flex-start;gap:16px;flex-wrap:wrap;">
      <div style="flex:1;min-width:200px;">
        <div style="display:flex;align-items:center;gap:10px;margin-bottom:8px;flex-wrap:wrap;">
          <span style="font-family:'Geist Mono',monospace;font-size:13px;font-weight:700;color:#E8940A;">@${escapeHtml(a.tiktok_username || '')}</span>
          ${statutBadge(a.statut)}
          ${a.code_affiliation ? `<span style="font-size:11px;color:var(--gris);font-family:'Geist Mono',monospace;">${escapeHtml(a.code_affiliation)}</span>` : ''}
        </div>
        <div style="display:flex;gap:16px;flex-wrap:wrap;">
          <div style="font-size:12px;color:var(--gris);">
            TikTok: <strong style="color:#FCE0A8;">${a.tiktok_followers ? (a.tiktok_followers >= 1000 ? Math.round(a.tiktok_followers/1000) + 'K' : a.tiktok_followers) : '?'} abonnés</strong>
          </div>
          ${a.instagram_username ? `<div style="font-size:12px;color:var(--gris);">Instagram: <strong style="color:#FCE0A8;">@${escapeHtml(a.instagram_username)} ${a.instagram_followers ? '(' + (a.instagram_followers >= 1000 ? Math.round(a.instagram_followers/1000) + 'K' : a.instagram_followers) + ')' : ''}</strong></div>` : ''}
        </div>
        <div style="font-size:11px;color:var(--gris);margin-top:6px;">${new Date(a.created_at).toLocaleDateString('fr-FR', { day:'2-digit', month:'short', year:'numeric' })}</div>
        ${a.notes_admin ? `<div style="font-size:12px;color:var(--gris);margin-top:6px;font-style:italic;">${escapeHtml(a.notes_admin)}</div>` : ''}
      </div>
      <div style="display:flex;flex-direction:column;gap:8px;flex-shrink:0;">
        ${a.statut !== 'valide' ? `<button onclick="validerAmbassadeur('${a.id}')" style="padding:8px 16px;background:#E8940A;color:#14100A;border:none;border-radius:8px;font-weight:700;font-size:12px;cursor:pointer;font-family:Geist,sans-serif;">Valider</button>` : ''}
        ${a.statut !== 'refuse' ? `<button onclick="refuserAmbassadeur('${a.id}')" style="padding:8px 16px;background:rgba(239,68,68,.15);border:1px solid rgba(239,68,68,.3);color:#ef4444;border-radius:8px;font-weight:700;font-size:12px;cursor:pointer;font-family:Geist,sans-serif;">Refuser</button>` : ''}
        ${a.user_id ? `<button onclick="openAmbassadeurProgressionModal('${a.user_id}','${escapeHtml(a.tiktok_username||'?')}')" style="padding:8px 16px;background:rgba(232,148,10,.1);border:1px solid rgba(232,148,10,.25);color:#E8940A;border-radius:8px;font-weight:700;font-size:12px;cursor:pointer;font-family:Geist,sans-serif;">Progression</button>` : ''}
      </div>
    </div>
  `).join('');
}

async function validerAmbassadeur(id) {
  const amb = _ambassadeursCache.find(a => a.id === id);
  if (!amb) return;

  // Générer un code affiliation unique : AMB-TIKTOK-XXXX
  const base = (amb.tiktok_username || 'AMB').toUpperCase().replace(/[^A-Z0-9]/g, '').slice(0, 8);
  const suffix = Math.floor(1000 + Math.random() * 9000);
  const code = `AMB-${base}-${suffix}`;

  try {
    const { error } = await supa
      .from('wozali_ambassadeurs')
      .update({
        statut: 'valide',
        code_affiliation: code,
        date_validation: new Date().toISOString(),
        valide_par: currentUser?.email || 'admin',
        pro_offert: true
      })
      .eq('id', id);

    if (error) { toast('La validation n\'est pas passée. Réessaie dans un instant.', 'error'); return; }

    // Si l'ambassadeur a un user_id, passer son compte Pro
    if (amb.user_id) {
      await supa
        .from('wozali_prestataires')
        .update({ abonnement: 'Pro', parrain_code: code })
        .eq('user_id', amb.user_id);
    }

    toast('Ambassadeur validé. Code : ' + code, 'success');
    await loadAdminAmbassadeurs();
  } catch (e) { console.error('[valider-amb]', e); toast('Ça n\'a pas marché. Réessaie dans un instant.', 'error'); }
}

async function refuserAmbassadeur(id) {
  try {
    const { error } = await supa
      .from('wozali_ambassadeurs')
      .update({ statut: 'refuse' })
      .eq('id', id);

    if (error) { toast('Ça n\'a pas marché. Réessaie dans un instant.', 'error'); return; }
    toast('Candidature refusée', 'info');
    await loadAdminAmbassadeurs();
  } catch (e) { console.error('[refuser-amb]', e); toast('Ça n\'a pas marché. Réessaie dans un instant.', 'error'); }
}

async function _adminToken() {
  const { data: { session } } = await supa.auth.getSession();
  return session?.access_token || '';
}

async function _agentsAPI(action, extra = {}) {
  const token = await _adminToken();
  const r = await fetch('/api/wozali-pay/agents-terrain', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ action, token, ...extra })
  });
  return r.json();
}

// ── AGENTS TERRAIN : chargement ──
async function loadAgentsTerrain() {
  if (!_isAdminDash) return;
  const d = await _agentsAPI('list');
  if (!d.ok) { toast('La liste n\'a pas chargé. Recharge la page.', 'error'); return; }
  _agentsTerrainCache = d.agents || [];
  // Enrichir avec le nombre de docs lus par agent
  await _enrichAgentsWithDocCounts();
  renderAgentsList();
  renderAgentsStats();
}

async function _enrichAgentsWithDocCounts() {
  const agentsWithUserId = _agentsTerrainCache.filter(a => a.actif && (a.user_id || a.id));
  if (!agentsWithUserId.length) return;
  try {
    const userIds = agentsWithUserId.map(a => a.user_id || a.id).filter(Boolean);
    const { data, error } = await supa
      .from('agent_document_reads')
      .select('agent_id')
      .in('agent_id', userIds);
    if (error || !data) return;
    // Compter par agent_id
    const counts = {};
    data.forEach(row => { counts[row.agent_id] = (counts[row.agent_id] || 0) + 1; });
    _agentsTerrainCache.forEach(a => {
      const uid = a.user_id || a.id;
      a.docs_lus = counts[uid] || 0;
    });
  } catch (e) { console.error('[enrich-doc-counts]', e); }
}

function renderAgentsStats() {
  const actifs = _agentsTerrainCache.filter(a => a.actif);
  const totalFilleuls = actifs.reduce((s, a) => s + (a.nb_filleuls || 0), 0);
  const totalComm = actifs.reduce((s, a) => s + (a.total_commissions || 0), 0);
  document.getElementById('agents-total-count').textContent = actifs.length;
  document.getElementById('agents-total-filleuls').textContent = totalFilleuls.toLocaleString('fr-FR');
  document.getElementById('agents-total-comm').textContent = totalComm.toLocaleString('fr-FR');
}

function filterAgentsVille(ville) {
  _agentsVilleFilter = ville;
  // UI boutons
  ['all', 'lome', 'cotonou'].forEach(k => {
    const btn = document.getElementById('agents-filter-' + k);
    if (!btn) return;
    const active = (k === 'all' && !ville) || (k === 'lome' && ville === 'Lomé') || (k === 'cotonou' && ville === 'Cotonou');
    btn.style.background = active ? '#E8940A' : 'rgba(255,255,255,.08)';
    btn.style.color = active ? '#14100A' : '#FCE0A8';
    btn.style.border = active ? 'none' : '1px solid rgba(255,255,255,.12)';
  });
  renderAgentsList();
}

function renderAgentsList() {
  const container = document.getElementById('agents-list');
  let agents = _agentsTerrainCache.filter(a => a.actif);
  if (_agentsVilleFilter) agents = agents.filter(a => a.ville === _agentsVilleFilter);

  if (!agents.length) {
    container.innerHTML = '<div style="text-align:center;padding:30px;color:var(--gris);font-size:13px;">Aucun agent trouvé. Utilise la recherche ci-dessus pour en ajouter.</div>';
    return;
  }

  // Trier par filleuls desc
  agents.sort((a, b) => (b.nb_filleuls || 0) - (a.nb_filleuls || 0));

  container.innerHTML = agents.map((a, i) => `
    <div style="display:flex;align-items:center;gap:12px;padding:12px 14px;background:rgba(255,255,255,.04);border:1px solid rgba(255,255,255,.08);border-radius:12px;flex-wrap:wrap;">
      <div style="width:32px;height:32px;border-radius:50%;background:${a.genre === 'F' ? 'rgba(232,148,10,.15)' : 'rgba(59,130,246,.15)'};display:flex;align-items:center;justify-content:center;font-size:14px;font-weight:800;color:${a.genre === 'F' ? '#E8940A' : '#3b82f6'};">${i + 1}</div>
      <div style="flex:1;min-width:0;">
        <div style="font-weight:700;font-size:14px;color:#FCE0A8;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${a.nom}</div>
        <div style="font-size:11px;color:var(--gris);">${a.ville} · ${a.genre === 'F' ? 'Femme' : 'Homme'} · ${a.telephone || '—'}</div>
      </div>
      <div style="text-align:right;min-width:60px;">
        <div style="font-family:'Geist Mono',monospace;font-size:13px;font-weight:900;color:${(a.docs_lus||0)===20?'#E8940A':'#FCE0A8'};">${a.docs_lus||0}/20</div>
        <div style="font-size:10px;color:var(--gris);">docs lus</div>
      </div>
      <div style="text-align:right;min-width:80px;">
        <div style="font-family:'Geist Mono',monospace;font-size:16px;font-weight:900;color:#FCE0A8;">${a.nb_filleuls || 0}</div>
        <div style="font-size:10px;color:var(--gris);">inscrits</div>
      </div>
      <div style="text-align:right;min-width:90px;">
        <div style="font-family:'Geist Mono',monospace;font-size:13px;color:#E8940A;">${(a.total_commissions || 0).toLocaleString('fr-FR')}</div>
        <div style="font-size:10px;color:var(--gris);">FCFA</div>
      </div>
      <button onclick="openAgentProgressionModal('${a.user_id||a.id}', ${JSON.stringify(a.nom)})" style="padding:6px 12px;border-radius:8px;border:1px solid rgba(232,148,10,.3);background:rgba(232,148,10,.08);color:#E8940A;font-size:11px;font-weight:700;cursor:pointer;white-space:nowrap;">Voir progression</button>
      <button onclick="removeAgent('${a.id}')" style="background:none;border:none;color:#dc2626;cursor:pointer;font-size:16px;padding:4px;" title="Retirer cet agent">✕</button>
    </div>
  `).join('');
}

async function removeAgent(agentId) {
  if (!confirm('Retirer cet agent terrain WOZALI ?')) return;
  const d = await _agentsAPI('remove', { agent_id: agentId });
  if (d.ok) {
    toast('Agent retiré', 'info');
    loadAgentsTerrain();
  } else {
    toast(d.error || 'Ça a calé. Réessaie dans 2 secondes.', 'error');
  }
}

// ── RECHERCHE PRESTATAIRE POUR AJOUT ──
function searchAgentDebounced() {
  clearTimeout(_agentSearchTimer);
  _agentSearchTimer = setTimeout(searchAgentNow, 400);
}

async function searchAgentNow() {
  const q = document.getElementById('agent-search-input')?.value?.trim();
  const container = document.getElementById('agent-search-results');
  if (!q || q.length < 2) { container.style.display = 'none'; return; }

  container.style.display = 'block';
  container.innerHTML = '<div style="padding:16px;text-align:center;color:var(--gris);font-size:13px;">Recherche en cours...</div>';

  const d = await _agentsAPI('search', { q });
  if (!d.ok || !d.results?.length) {
    container.innerHTML = '<div style="padding:16px;text-align:center;color:var(--gris);font-size:13px;">Aucun prestataire trouvé pour "' + q + '"</div>';
    return;
  }

  // Vérifier lesquels sont déjà agents
  const existingTels = new Set(_agentsTerrainCache.map(a => a.telephone).filter(Boolean));

  container.innerHTML = d.results.map(r => {
    const isAlready = existingTels.has(r.telephone);
    return `
      <div style="display:flex;align-items:center;gap:12px;padding:10px 12px;border-bottom:1px solid rgba(255,255,255,.06);${isAlready ? 'opacity:.5;' : ''}">
        <div style="width:40px;height:40px;border-radius:50%;background:rgba(255,255,255,.08);overflow:hidden;flex-shrink:0;">
          ${r.photo ? `<img src="${r.photo}" style="width:100%;height:100%;object-fit:cover;" loading="lazy">` : '<div style="width:100%;height:100%;display:flex;align-items:center;justify-content:center;font-size:16px;">👤</div>'}
        </div>
        <div style="flex:1;min-width:0;">
          <div style="font-weight:700;font-size:13px;color:#FCE0A8;">${r.nom}</div>
          <div style="font-size:11px;color:var(--gris);">${r.telephone || '—'} · ${r.metier || '—'} · ${r.quartier || '—'}</div>
          <div style="font-size:10px;color:${r.abonnement === 'Pro' ? '#E8940A' : 'var(--gris)'};">${r.abonnement} ${r.code_parrainage ? '· Code: ' + r.code_parrainage : ''}</div>
        </div>
        ${isAlready
          ? '<span style="font-size:11px;color:var(--gris);white-space:nowrap;">Déjà agent</span>'
          : `<div style="display:flex;gap:4px;">
              <button onclick="addAgentModal('${encodeURIComponent(JSON.stringify(r))}')" style="padding:6px 12px;background:#E8940A;color:#14100A;border:none;border-radius:8px;font-size:11px;font-weight:700;cursor:pointer;">+ Ajouter</button>
            </div>`
        }
      </div>
    `;
  }).join('');
}

