const _contratCanvasBound = {}; // évite de re-binder les events canvas

function initContratCanvas(type) {
  const canvas = document.getElementById('contrat-canvas-' + type);
  const hintId = 'contrat-canvas-' + type + '-hint';
  if (!canvas || _contratCanvasBound[type]) return;
  _contratCanvasBound[type] = true;
  const ctx = canvas.getContext('2d');
  ctx.strokeStyle = '#FCE0A8';
  ctx.lineWidth = 2.5;
  ctx.lineCap = 'round';
  ctx.lineJoin = 'round';
  let drawing = false;

  function getPos(e) {
    const r = canvas.getBoundingClientRect();
    const src = e.touches ? e.touches[0] : e;
    return {
      x: (src.clientX - r.left) * (canvas.width / r.width),
      y: (src.clientY - r.top) * (canvas.height / r.height),
    };
  }
  function startDraw(e) {
    e.preventDefault();
    drawing = true;
    const hint = document.getElementById(hintId);
    if (hint) hint.style.display = 'none';
    const { x, y } = getPos(e);
    ctx.beginPath(); ctx.moveTo(x, y);
  }
  function draw(e) {
    e.preventDefault();
    if (!drawing) return;
    const { x, y } = getPos(e);
    ctx.lineTo(x, y); ctx.stroke();
  }
  function stopDraw() { drawing = false; }

  canvas.addEventListener('mousedown', startDraw);
  canvas.addEventListener('mousemove', draw);
  canvas.addEventListener('mouseup', stopDraw);
  canvas.addEventListener('mouseleave', stopDraw);
  canvas.addEventListener('touchstart', startDraw, { passive: false });
  canvas.addEventListener('touchmove', draw, { passive: false });
  canvas.addEventListener('touchend', stopDraw);
}

function clearContratCanvas(type) {
  const canvas = document.getElementById('contrat-canvas-' + type);
  if (!canvas) return;
  canvas.getContext('2d').clearRect(0, 0, canvas.width, canvas.height);
  const hint = document.getElementById('contrat-canvas-' + type + '-hint');
  if (hint) hint.style.display = 'flex';
}

function _isCanvasEmpty(canvas) {
  const d = canvas.getContext('2d').getImageData(0, 0, canvas.width, canvas.height).data;
  return !d.some(v => v !== 0);
}

async function loadAgentContrat() {
  if (!currentUser) return;
  const p = currentPrestataire || {};
  const nomInput = document.getElementById('contrat-nom');
  const telInput = document.getElementById('contrat-telephone');
  if (nomInput && p.nom && !nomInput.value) nomInput.value = p.nom;
  if (telInput && p.telephone && !telInput.value) telInput.value = p.telephone;

  const statusBlock = document.getElementById('contrat-status-block');
  const signForm   = document.getElementById('contrat-sign-form');
  const signeView  = document.getElementById('contrat-signe-view');
  if (!statusBlock) return;
  statusBlock.innerHTML = '<div style="text-align:center;padding:16px;color:rgba(252,224,168,.3);font-size:13px;">Verification...</div>';

  try {
    // Charger les deux documents (contrat + charte)
    const { data: docs, error } = await supa
      .from('agent_contrats')
      .select('*')
      .eq('agent_id', currentUser.id)
      .in('document_type', ['contrat', 'charte']);
    if (error) throw error;

    const contrat = (docs || []).find(d => d.document_type === 'contrat');
    const charte  = (docs || []).find(d => d.document_type === 'charte');
    const allSigned = contrat && charte;
    const dot = document.getElementById('agent-contrat-dot');
    if (dot) dot.style.display = allSigned ? 'none' : 'block';

    function _badge(doc, label, slug, contractRef) {
      if (!doc) return `<div style="display:flex;gap:12px;align-items:center;padding:12px 14px;background:rgba(248,113,113,.06);border:1px solid rgba(248,113,113,.18);border-radius:10px;">
        <div style="font-size:20px;flex-shrink:0;">📄</div>
        <div style="flex:1;">
          <div style="font-size:13px;font-weight:700;color:#f87171;margin-bottom:2px;">${label} — Non signe</div>
          <div style="font-size:12px;color:rgba(252,224,168,.45);">Ouvre le document et signe directement.</div>
        </div>
        <a href="/formation-responsable/${slug}.html" target="_blank" style="flex-shrink:0;padding:8px 12px;background:#E8940A;color:#14100A;font-size:11px;font-weight:700;border-radius:7px;text-decoration:none;font-family:'Geist Mono',monospace;white-space:nowrap;">Signer →</a>
      </div>`;
      if (doc.statut === 'cosigne') {
        const d = doc.fondateur_signed_at ? new Date(doc.fondateur_signed_at).toLocaleDateString('fr-FR') : '-';
        return `<div style="display:flex;gap:12px;align-items:center;padding:12px 14px;background:rgba(232,148,10,.06);border:1px solid rgba(232,148,10,.18);border-radius:10px;">
          <div style="font-size:20px;flex-shrink:0;">✅</div>
          <div style="flex:1;"><div style="font-size:13px;font-weight:700;color:#E8940A;margin-bottom:2px;">${label} — Valide</div><div style="font-size:12px;color:rgba(252,224,168,.45);">Cosigne le ${d}.</div></div>
          <a href="/formation-responsable/${slug}.html" target="_blank" style="flex-shrink:0;padding:6px 10px;background:rgba(232,148,10,.1);border:1px solid rgba(232,148,10,.2);color:#E8940A;font-size:11px;font-weight:700;border-radius:7px;text-decoration:none;font-family:'Geist Mono',monospace;">Voir →</a>
        </div>`;
      }
      const d = doc.signed_at ? new Date(doc.signed_at).toLocaleDateString('fr-FR') : '-';
      return `<div style="display:flex;gap:12px;align-items:center;padding:12px 14px;background:rgba(232,148,10,.06);border:1px solid rgba(232,148,10,.18);border-radius:10px;">
        <div style="font-size:20px;flex-shrink:0;">✍️</div>
        <div style="flex:1;"><div style="font-size:13px;font-weight:700;color:#E8940A;margin-bottom:2px;">${label} — Signe le ${d}</div><div style="font-size:12px;color:rgba(252,224,168,.45);">En attente de contresignature du fondateur.</div></div>
        <a href="/formation-responsable/${slug}.html" target="_blank" style="flex-shrink:0;padding:6px 10px;background:rgba(232,148,10,.1);border:1px solid rgba(232,148,10,.2);color:#E8940A;font-size:11px;font-weight:700;border-radius:7px;text-decoration:none;font-family:'Geist Mono',monospace;">Voir →</a>
      </div>`;
    }

    statusBlock.innerHTML = `<div style="display:flex;flex-direction:column;gap:10px;">
      ${_badge(contrat, 'Contrat de mission', 'rt-18-contrat-agent-terrain', 'RT-CT-2026-018')}
      ${_badge(charte,  'Charte deontologique', 'rt-12-charte-deontologique', 'RT-CD-2026-012')}
    </div>`;

    // Formulaire dashboard : signer le contrat uniquement si non signe
    if (!contrat) {
      if (signForm) { signForm.style.display = 'block'; setTimeout(() => initContratCanvas('agent'), 80); }
      if (signeView) signeView.style.display = 'none';
    } else {
      if (signForm) signForm.style.display = 'none';
      if (signeView) { signeView.style.display = 'block'; _renderContratSigneAgent(contrat); }
    }
  } catch(err) {
    console.error('[loadAgentContrat]', err);
    statusBlock.innerHTML = '<div style="color:#ef4444;font-size:13px;padding:12px;">Erreur de chargement. Rafraichis la page.</div>';
  }
}

function _renderContratSigneAgent(data) {
  const el = document.getElementById('contrat-signe-view');
  if (!el) return;
  const dSign = data.signed_at ? new Date(data.signed_at).toLocaleDateString('fr-FR', { day: '2-digit', month: 'long', year: 'numeric' }) : '-';
  el.innerHTML = `
    <div style="background:#161616;border:1px solid rgba(232,148,10,.15);border-radius:14px;padding:20px;">
      <div style="font-family:'Geist Mono',monospace;font-size:10px;color:#E8940A;text-transform:uppercase;letter-spacing:2px;margin-bottom:14px;">Recapitulatif contrat</div>
      <div style="display:grid;gap:10px;margin-bottom:16px;">
        <div><span style="font-size:11px;color:rgba(252,224,168,.4);">Nom :</span> <span style="font-size:13px;color:#FCE0A8;font-weight:600;">${data.agent_nom||'-'}</span></div>
        <div><span style="font-size:11px;color:rgba(252,224,168,.4);">Telephone :</span> <span style="font-size:13px;color:#FCE0A8;">${data.agent_telephone||'-'}</span></div>
        <div><span style="font-size:11px;color:rgba(252,224,168,.4);">Ville :</span> <span style="font-size:13px;color:#FCE0A8;">${data.agent_ville||'-'}</span></div>
        <div><span style="font-size:11px;color:rgba(252,224,168,.4);">Fait a :</span> <span style="font-size:13px;color:#FCE0A8;">${data.lieu_signature||'-'}</span></div>
        <div><span style="font-size:11px;color:rgba(252,224,168,.4);">Date signature :</span> <span style="font-size:13px;color:#FCE0A8;">${dSign}</span></div>
      </div>
      ${data.signature_data_url ? `<div style="margin-top:14px;padding-top:14px;border-top:1px solid rgba(232,148,10,.1);"><div style="font-size:11px;color:rgba(252,224,168,.4);margin-bottom:8px;">Ta signature :</div><div style="background:#111;border:1px solid rgba(255,255,255,.06);border-radius:8px;overflow:hidden;height:80px;display:flex;align-items:center;justify-content:center;"><img src="${data.signature_data_url}" alt="Signature" style="max-width:100%;max-height:80px;object-fit:contain;"/></div></div>` : ''}
      ${data.fondateur_signature_data_url ? `<div style="margin-top:12px;"><div style="font-size:11px;color:rgba(252,224,168,.4);margin-bottom:8px;">Contresignature fondateur :</div><div style="background:#111;border:1px solid rgba(232,148,10,.12);border-radius:8px;overflow:hidden;height:80px;display:flex;align-items:center;justify-content:center;"><img src="${data.fondateur_signature_data_url}" alt="Contresignature" style="max-width:100%;max-height:80px;object-fit:contain;"/></div></div>` : ''}
    </div>
    <div style="margin-top:12px;text-align:center;"><a href="/formation-responsable/rt-18-contrat-agent-terrain.html" target="_blank" style="font-size:12px;color:#E8940A;text-decoration:none;font-family:'Geist Mono',monospace;">Voir le contrat complet &rarr;</a></div>`;
}

async function submitAgentContrat() {
  const nom       = (document.getElementById('contrat-nom')?.value || '').trim();
  const telephone = (document.getElementById('contrat-telephone')?.value || '').trim();
  const ville     = document.getElementById('contrat-ville')?.value || '';
  const lieu      = (document.getElementById('contrat-lieu')?.value || '').trim();
  const lu        = document.getElementById('contrat-lu')?.checked;
  const canvas    = document.getElementById('contrat-canvas-agent');

  if (!nom)                                    { toast('Entre ton nom complet', 'error'); return; }
  if (!ville)                                  { toast('Selectionne ta ville', 'error'); return; }
  if (!lu)                                     { toast('Coche "Lu et approuve" pour continuer', 'error'); return; }
  if (!canvas || _isCanvasEmpty(canvas))       { toast('Dessine ta signature dans le cadre', 'error'); return; }

  const btn = document.getElementById('btn-signer-contrat');
  if (btn) { btn.disabled = true; btn.textContent = 'Signature en cours...'; }

  try {
    const signatureDataUrl = canvas.toDataURL('image/png');
    const now = new Date();
    const { error } = await supa.from('agent_contrats').upsert({
      agent_id:           currentUser.id,
      document_type:      'contrat',
      agent_nom:          nom,
      agent_telephone:    telephone,
      agent_ville:        ville,
      lieu_signature:     lieu || ville,
      date_signature:     now.toISOString().split('T')[0],
      signature_data_url: signatureDataUrl,
      signed_at:          now.toISOString(),
      statut:             'agent_signe',
      contract_ref:       'RT-CT-2026-018',
    }, { onConflict: 'agent_id,document_type' });
    if (error) throw error;

    toast('Contrat signe. En attente de contresignature.', 'success');
    const dot = document.getElementById('agent-contrat-dot');
    if (dot) dot.style.display = 'none';
    await loadAgentContrat();
  } catch(err) {
    console.error('[submitAgentContrat]', err);
    toast('La signature n\'est pas passée. Réessaie dans un instant.', 'error');
    if (btn) { btn.disabled = false; btn.textContent = 'Signer le contrat'; }
  }
}

// ── Admin : liste des contrats ──

async function loadAdminContrats() {
  const listEl    = document.getElementById('admin-contrats-list');
  const totalEl   = document.getElementById('admin-contrats-total');
  const signesEl  = document.getElementById('admin-contrats-signes');
  const cosEl     = document.getElementById('admin-contrats-cosignes');
  if (!listEl) return;
  listEl.innerHTML = '<div style="text-align:center;padding:30px;color:rgba(252,224,168,.25);font-size:13px;">Chargement...</div>';

  try {
    const { data, error } = await supa
      .from('agent_contrats')
      .select('id, agent_nom, agent_telephone, agent_ville, signed_at, fondateur_signed_at, statut')
      .order('signed_at', { ascending: false });
    if (error) throw error;

    const all      = data || [];
    const agentIds = [...new Set(all.map(c => c.agent_id))];
    const aSign    = all.filter(c => c.statut === 'agent_signe').length;
    const cosignes = all.filter(c => c.statut === 'cosigne').length;
    if (totalEl)  totalEl.textContent  = agentIds.length;
    if (signesEl) signesEl.textContent = aSign;
    if (cosEl)    cosEl.textContent    = cosignes;

    if (all.length === 0) {
      listEl.innerHTML = '<div style="text-align:center;padding:30px;color:rgba(252,224,168,.2);font-size:13px;">Aucun contrat signe pour l\'instant.</div>';
      return;
    }

    // Grouper par agent (nom + ville), chaque agent peut avoir 2 docs
    const byAgent = {};
    all.forEach(c => {
      const key = c.agent_id;
      if (!byAgent[key]) byAgent[key] = { nom: c.agent_nom, ville: c.agent_ville, tel: c.agent_telephone, docs: {} };
      byAgent[key].docs[c.document_type] = c;
    });

    listEl.innerHTML = Object.values(byAgent).map(agent => {
      const contrat = agent.docs['contrat'];
      const charte  = agent.docs['charte'];
      const allCo   = contrat?.statut === 'cosigne' && charte?.statut === 'cosigne';
      const borderColor = allCo ? 'rgba(232,148,10,.15)' : 'rgba(255,255,255,.06)';

      function docRow(doc, label, slug) {
        if (!doc) return `<div style="display:flex;align-items:center;gap:8px;padding:6px 0;">
          <span style="font-size:11px;color:rgba(252,224,168,.3);font-family:'Geist Mono',monospace;min-width:80px;">${label}</span>
          <span style="font-size:11px;color:#f87171;">Non signe</span>
        </div>`;
        const isCo = doc.statut === 'cosigne';
        const ds   = doc.signed_at ? new Date(doc.signed_at).toLocaleDateString('fr-FR') : '-';
        const dc   = doc.fondateur_signed_at ? new Date(doc.fondateur_signed_at).toLocaleDateString('fr-FR') : '-';
        return `<div style="display:flex;align-items:center;gap:8px;padding:6px 0;flex-wrap:wrap;">
          <span style="font-size:11px;color:rgba(252,224,168,.4);font-family:'Geist Mono',monospace;min-width:80px;">${label}</span>
          <span style="font-size:11px;color:${isCo ? '#E8940A' : '#E8940A'};font-weight:700;">${isCo ? 'Cosigne' : 'A contresigner'}</span>
          <span style="font-size:11px;color:rgba(252,224,168,.3);">${isCo ? dc : ds}</span>
          ${!isCo ? `<button type="button" onclick="openCosignModal('${doc.id}')" style="margin-left:auto;padding:4px 10px;background:#E8940A;color:#14100A;border:none;border-radius:6px;font-size:11px;font-weight:700;cursor:pointer;font-family:'Geist',sans-serif;">Contresigner</button>` : ''}
        </div>`;
      }

      return `<div style="background:#161616;border:1px solid ${borderColor};border-radius:12px;padding:14px 16px;margin-bottom:8px;">
        <div style="display:flex;align-items:flex-start;gap:10px;margin-bottom:10px;">
          <div style="flex:1;">
            <div style="font-size:14px;font-weight:700;color:#FCE0A8;">${agent.nom||'-'}</div>
            <div style="font-size:12px;color:rgba(252,224,168,.4);margin-top:2px;">${agent.ville||'-'} &middot; ${agent.tel||'-'}</div>
          </div>
          ${allCo ? '<span style="font-size:10px;font-family:\'Geist Mono\',monospace;color:#E8940A;border:1px solid rgba(232,148,10,.25);padding:3px 8px;border-radius:20px;">Complet</span>' : ''}
        </div>
        <div style="border-top:1px solid rgba(255,255,255,.05);padding-top:8px;">
          ${docRow(contrat, 'Contrat', 'rt-18-contrat-agent-terrain')}
          ${docRow(charte,  'Charte',  'rt-12-charte-deontologique')}
        </div>
      </div>`;
    }).join('');
  } catch(err) {
    console.error('[loadAdminContrats]', err);
    listEl.innerHTML = '<div style="color:#ef4444;font-size:13px;padding:12px;">Erreur de chargement.</div>';
  }
}

let _cosignContratId = null;

async function openCosignModal(contratId) {
  _cosignContratId = contratId;
  document.getElementById('cosign-contrat-id').value = contratId;

  // Charger les détails complets (dont signature_data_url)
  try {
    const { data, error } = await supa
      .from('agent_contrats')
      .select('*')
      .eq('id', contratId)
      .single();
    if (error || !data) { toast('Le contrat n\'a pas chargé. Recharge la page ou réessaie plus tard.', 'error'); return; }

    document.getElementById('modal-cosign-ref').textContent = 'RT-CT-2026-018 - ' + (data.agent_nom || '');

    const infoEl = document.getElementById('modal-cosign-agent-info');
    if (infoEl) {
      const ds = data.signed_at ? new Date(data.signed_at).toLocaleDateString('fr-FR', { day: '2-digit', month: 'long', year: 'numeric' }) : '-';
      infoEl.innerHTML = `<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;">
        <div><span style="font-size:10px;color:rgba(252,224,168,.4);">Agent :</span><br/><span style="font-size:13px;color:#FCE0A8;">${data.agent_nom||'-'}</span></div>
        <div><span style="font-size:10px;color:rgba(252,224,168,.4);">Ville :</span><br/><span style="font-size:13px;color:#FCE0A8;">${data.agent_ville||'-'}</span></div>
        <div><span style="font-size:10px;color:rgba(252,224,168,.4);">Tel :</span><br/><span style="font-size:13px;color:#FCE0A8;">${data.agent_telephone||'-'}</span></div>
        <div><span style="font-size:10px;color:rgba(252,224,168,.4);">Signe le :</span><br/><span style="font-size:13px;color:#FCE0A8;">${ds}</span></div>
      </div>`;
    }

    const imgEl = document.getElementById('modal-agent-sig-img');
    if (imgEl) imgEl.src = data.signature_data_url || '';

    // Reset canvas fondateur
    _contratCanvasBound['fondateur'] = false;
    const cv = document.getElementById('contrat-canvas-fondateur');
    if (cv) cv.getContext('2d').clearRect(0, 0, cv.width, cv.height);
    const hint = document.getElementById('contrat-canvas-fondateur-hint');
    if (hint) hint.style.display = 'flex';

    document.getElementById('modal-cosign').style.display = 'flex';
    setTimeout(() => initContratCanvas('fondateur'), 80);
  } catch(err) {
    console.error('[openCosignModal]', err);
    toast('Ça n\'a pas voulu s\'ouvrir. Recharge la page et réessaie.', 'error');
  }
}

async function submitFondateurCosign() {
  const contratId = _cosignContratId;
  if (!contratId) return;
  const canvas = document.getElementById('contrat-canvas-fondateur');
  if (!canvas || _isCanvasEmpty(canvas)) { toast('Ajoute ta contresignature', 'error'); return; }

  const btn = document.getElementById('btn-cosigner');
  if (btn) { btn.disabled = true; btn.textContent = 'Signature en cours...'; }

  try {
    const sigDataUrl = canvas.toDataURL('image/png');
    const now = new Date().toISOString();
    const { error } = await supa.from('agent_contrats').update({
      fondateur_signature_data_url: sigDataUrl,
      fondateur_signed_at: now,
      statut: 'cosigne',
    }).eq('id', contratId);
    if (error) throw error;

    toast('Contrat contresigne avec succes', 'success');
    document.getElementById('modal-cosign').style.display = 'none';
    _cosignContratId = null;
    await loadAdminContrats();
  } catch(err) {
    console.error('[submitFondateurCosign]', err);
    toast('La contresignature n\'est pas passée. Réessaie dans un instant.', 'error');
    if (btn) { btn.disabled = false; btn.textContent = 'Contresigner et valider'; }
  }
}

async function loadAgentJournalSection() {
  if (!currentUser) return;
  const now = new Date();
  const dateLabel = now.toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long' });
  const dateEl = document.getElementById('journal-date-label');
  if (dateEl) dateEl.textContent = dateLabel;

  // Charger les journaux existants
  try {
    const { data, error } = await supa
      .from('agent_journaux_terrain')
      .select('*')
      .eq('agent_id', currentUser.id)
      .order('date', { ascending: false })
      .limit(10);
    if (!error) _renderAgentJournaux(data || []);
  } catch (e) { console.error('[journal-load]', e); }
}

function _renderAgentJournaux(rows) {
  const el = document.getElementById('agent-journaux-list');
  if (!el) return;
  if (!rows.length) {
    el.innerHTML = '<div style="text-align:center;padding:32px;color:rgba(252,224,168,.25);font-size:13px;">Aucun journal soumis encore. Soumets ton premier ce soir.</div>';
    return;
  }
  el.innerHTML = rows.map(r => {
    const d = new Date(r.date + 'T12:00:00');
    const label = d.toLocaleDateString('fr-FR', { weekday: 'short', day: 'numeric', month: 'short' });
    const pct = r.inscrits > 0 ? Math.round(r.pros / r.inscrits * 100) : 0;
    const convColor = r.inscrits >= 8 ? '#E8940A' : r.inscrits >= 4 ? '#f59e0b' : '#f87171';
    return `
      <div style="background:#161616;border:1px solid rgba(255,255,255,.06);border-radius:14px;padding:16px;">
        <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:10px;">
          <div style="font-family:'Geist Mono',monospace;font-size:12px;font-weight:700;color:#FCE0A8;">${label}</div>
          <div style="display:flex;gap:10px;font-size:12px;font-family:'Geist Mono',monospace;">
            <span style="color:rgba(252,224,168,.4);">${r.conversations || 0} conv.</span>
            <span style="color:${convColor};font-weight:700;">${r.inscrits || 0} inscrits</span>
            <span style="color:#E8940A;font-weight:900;">${r.pros || 0} Pros</span>
            ${r.inscrits > 0 ? `<span style="color:rgba(252,224,168,.4);">(${pct}%)</span>` : ''}
          </div>
        </div>
        ${r.zones ? `<div style="font-size:11px;color:rgba(252,224,168,.35);margin-bottom:8px;">Zones : ${r.zones}</div>` : ''}
        <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px;font-size:11px;">
          ${r.ce_qui_a_marche ? `<div style="background:rgba(232,148,10,.04);border:1px solid rgba(232,148,10,.1);border-radius:8px;padding:8px;color:rgba(252,224,168,.6);line-height:1.4;"><span style="color:#E8940A;font-weight:700;display:block;margin-bottom:3px;">Marche</span>${r.ce_qui_a_marche}</div>` : ''}
          ${r.ce_qui_na_pas_marche ? `<div style="background:rgba(239,68,68,.04);border:1px solid rgba(239,68,68,.1);border-radius:8px;padding:8px;color:rgba(252,224,168,.6);line-height:1.4;"><span style="color:#f87171;font-weight:700;display:block;margin-bottom:3px;">Pas marche</span>${r.ce_qui_na_pas_marche}</div>` : ''}
          ${r.demain_je_change ? `<div style="background:rgba(232,148,10,.04);border:1px solid rgba(232,148,10,.1);border-radius:8px;padding:8px;color:rgba(252,224,168,.6);line-height:1.4;"><span style="color:#E8940A;font-weight:700;display:block;margin-bottom:3px;">Demain</span>${r.demain_je_change}</div>` : ''}
        </div>
      </div>`;
  }).join('');
}

async function saveAgentJournal() {
  if (!currentUser) return;
  const btn = document.getElementById('journal-submit-btn');
  const msg = document.getElementById('journal-submit-msg');
  if (btn) { btn.disabled = true; btn.textContent = 'Envoi...'; }

  const now = new Date();
  const dateStr = now.toISOString().split('T')[0];
  const payload = {
    agent_id: currentUser.id,
    date: dateStr,
    conversations: parseInt(document.getElementById('journal-conversations')?.value) || 0,
    inscrits: parseInt(document.getElementById('journal-inscrits')?.value) || 0,
    pros: parseInt(document.getElementById('journal-pros')?.value) || 0,
    zones: (document.getElementById('journal-zones')?.value || '').trim(),
    ce_qui_a_marche: (document.getElementById('journal-marche')?.value || '').trim(),
    ce_qui_na_pas_marche: (document.getElementById('journal-pas-marche')?.value || '').trim(),
    demain_je_change: (document.getElementById('journal-demain')?.value || '').trim(),
    submitted_at: now.toISOString(),
  };

  try {
    const { error } = await supa
      .from('agent_journaux_terrain')
      .upsert(payload, { onConflict: 'agent_id,date' });
    if (error) throw error;
    if (msg) { msg.style.display = 'block'; msg.textContent = 'Journal envoye ! Ton Responsable le lit demain matin.'; }
    // Reset form
    ['journal-conversations','journal-inscrits','journal-pros','journal-zones','journal-marche','journal-pas-marche','journal-demain']
      .forEach(id => { const el = document.getElementById(id); if (el) el.value = ''; });
    updateJournalKpiColors();
    loadAgentJournalSection();
  } catch (e) {
    console.error('[journal-save]', e);
    if (msg) { msg.style.display = 'block'; msg.style.color = '#f87171'; msg.textContent = 'Erreur. Reessaie dans 2 secondes.'; }
  } finally {
    if (btn) { btn.disabled = false; btn.textContent = 'Envoyer mon journal →'; }
  }
}

